const LoadGameModal = ({ savedGames, loadGame, setShowLoadGameModal, setConfirmationModal, userId, setModalMessage, db, appId }) => (
    <div className="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center p-4 z-50 animate-fade-in">
      <div className="bg-gray-800 p-6 rounded-xl shadow-2xl w-full max-w-2xl max-h-[85vh] flex flex-col border border-blue-600">
        <h2 className="text-2xl font-bold text-blue-400 mb-4 flex items-center">
            <ArrowPathIcon className="w-7 h-7 mr-2"/> Tải Game Đã Lưu
        </h2>
        
        {savedGames.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-500">
              <FolderOpenIcon className="w-16 h-16 mb-4 opacity-50"/>
              <p>Ngươi chưa có cuộc phiêu lưu nào được lưu lại.</p>
          </div>
        ) : (
          <div className="overflow-y-auto space-y-3 pr-2 scrollbar-thin scrollbar-thumb-blue-600 scrollbar-track-gray-700">
            {savedGames.map(game => {
              // Phân loại Slot hoặc Auto Save
              let slotLabel = "Bản Lưu";
              let labelColor = "bg-gray-600 text-gray-200";
              
              if (game.isAutosave) {
                  slotLabel = "AUTO SAVE";
                  labelColor = "bg-yellow-600/80 text-white";
              } else if (game.id && game.id.includes("manual_")) {
                  const slotNum = game.id.split('_')[1];
                  slotLabel = `SLOT ${slotNum}`;
                  labelColor = "bg-purple-600/80 text-white";
              }

              return (
              <div key={game.id} className="bg-gray-700 p-4 rounded-lg hover:bg-gray-600 transition-colors shadow-md border border-gray-600 hover:border-blue-400 group">
                <div className="flex justify-between items-start mb-2">
                    <span className={`text-xs font-bold px-2 py-1 rounded ${labelColor}`}>
                        {slotLabel}
                    </span>
                    <span className="text-xs text-gray-400 font-mono">
                        {game.updatedAt?.toDate ? new Date(game.updatedAt.toDate()).toLocaleString('vi-VN') : "N/A"}
                    </span>
                </div>

                <div className="grid grid-cols-2 gap-2 mb-3">
                    <div className="text-purple-300 font-semibold truncate flex items-center">
                        <UserCircleIcon className="w-4 h-4 mr-1.5"/>
                        {game.gameSettings?.characterName || "Vô Danh"}
                    </div>
                    <div className="text-sky-300 truncate flex items-center justify-end">
                        {game.gameSettings?.storyTitle || "Thế Giới Vô Danh"}
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4 ml-1.5"><path fillRule="evenodd" d="M9.69 18.933.003.001a9.7 9.7 0 0 1-2.92-1.928 9.7 9.7 0 0 1-2.226-3.111l-.001-.002A9.7 9.7 0 0 1 3 9.75c0-4.42 3.58-8 8-8s8 3.58 8 8a9.7 9.7 0 0 1-.547 3.142l-.001.002a9.7 9.7 0 0 1-2.226 3.111 9.7 9.7 0 0 1-2.92 1.928l-.003.001a.75.75 0 0 1-.74 0ZM8.5 9.75a2.25 2.25 0 1 0 4.5 0 2.25 2.25 0 0 0-4.5 0Z" clipRule="evenodd" /></svg>
                    </div>
                </div>

                <div className="flex justify-between items-center text-sm text-gray-400 border-t border-gray-600/50 pt-2 mb-3">
                     <span>Độ khó: <span className="text-gray-300">{game.gameSettings?.difficulty || "Thường"}</span></span>
                     <span className="text-yellow-500 font-mono">Lượt: {game.currentTurn || 0}</span>
                </div>

                <div className="flex space-x-2 opacity-80 group-hover:opacity-100 transition-opacity">
                    <button
                        onClick={() => loadGame(game)}
                        className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-3 rounded text-sm shadow flex items-center justify-center gap-2"
                    >
                        <PlayIcon className="w-4 h-4"/> Tiếp Tục
                    </button>
                    <button
                        onClick={() => {
                            setConfirmationModal({
                                show: true,
                                title: 'Xác Nhận Xóa',
                                content: `Bạn có chắc chắn muốn xóa bản lưu "${slotLabel}" này không?`,
                                onConfirm: async () => {
                                    try {
                                        await deleteDoc(doc(db, `artifacts/${appId}/users/${userId}/games`, game.id));
                                        setModalMessage({ show: true, title: 'Đã Xóa', content: 'Đã xóa bản lưu thành công.', type: 'success' });
                                    } catch (error) {
                                        console.error("Error deleting game:", error);
                                        setModalMessage({ show: true, title: 'Lỗi', content: error.message, type: 'error' });
                                    }
                                },
                                confirmText: "Xóa Vĩnh Viễn",
                                cancelText: "Hủy"
                            });
                        }}
                        className="bg-red-900/50 hover:bg-red-600 text-red-200 hover:text-white font-semibold py-2 px-3 rounded text-sm shadow border border-red-800 hover:border-transparent transition-all"
                    >
                        <TrashIcon className="w-4 h-4"/>
                    </button>
                </div>
              </div>
            )})}
          </div>
        )}
        <button
          onClick={() => setShowLoadGameModal(false)}
          className="mt-6 w-full bg-gray-700 hover:bg-gray-600 text-white font-semibold py-3 px-4 rounded-lg shadow-md transition-colors"
        >
          Đóng
        </button>
      </div>
    </div>
);

const app = initializeApp(firebaseConfig);
const auth = getAuth(app);
const db = getFirestore(app);

const appId = typeof __app_id !== 'undefined' ? __app_id : 'ai-text-adventure-simulator-vn';

