const BALANCING_RULES = `
// =======================================================================
// --- BỘ LUẬT CƠ SỞ VỀ YÊU CẦU SỬ DỤNG ('Requirements') V2.1 ---
// =======================================================================
// Ngươi PHẢI tuân thủ quy trình dưới đây để tạo ra thuộc tính "Requirements" một cách cân bằng.

// --- BƯỚC 1: XÁC ĐỊNH CẤP ĐỘ TỐI THIỂU DỰA TRÊN PHẨM CHẤT ---
// Dựa vào phẩm chất của vật phẩm, chọn một cấp độ yêu cầu trong khoảng tương ứng:
//   - Thường: Cấp 1-5
//   - Tốt: Cấp 5-10
//   - Hiếm: Cấp 15-20
//   - Cực Phẩm: Cấp 25
//   - Siêu Phẩm: Cấp 30
//   - Huyền Thoại: Cấp 35+

// --- BƯỚC 2: TÍNH NGÂN SÁCH YÊU CẦU ---
// Mỗi phẩm chất có một "Ngân Sách Yêu Cầu" (điểm) cố định để "mua" các yêu cầu:
//   - Thường: 1 điểm
//   - Tốt: 35 điểm
//   - Hiếm: 70 điểm
//   - Cực Phẩm: 120 điểm
//   - Siêu Phẩm: 170 điểm
//   - Huyền Thoại: 220 điểm

// --- BƯỚC 2.5 (MỚI): ĐIỀU CHỈNH NGÂN SÁCH CHO LỐI BUILD THUẦN KHIẾT ---
// - SAU KHI đã trừ đi điểm cho yêu cầu Cấp độ, hãy xem xét ngân sách còn lại.
// - NẾU vật phẩm chỉ yêu cầu **MỘT** chỉ số chiến đấu duy nhất (ví dụ: một thanh kiếm chỉ cần ATK), ngươi chỉ được dùng **75% (3/4)** ngân sách còn lại để "mua" yêu cầu cho chỉ số đó.
// - NẾU vật phẩm yêu cầu **HAI** chỉ số chiến đấu khác nhau (ví dụ: một bộ giáp cần cả DEF và HP), ngươi PHẢI dùng **TOÀN BỘ** ngân sách còn lại.

// --- BƯỚC 3: "MUA" YÊU CẦU BẰNG NGÂN SÁCH ---
// 1. Dùng ngân sách để "mua" yêu cầu Cấp độ đã chọn ở Bước 1.
// 2. Áp dụng quy tắc ở Bước 2.5 để xác định ngân sách cuối cùng cho các chỉ số.
// 3. Dùng TOÀN BỘ ngân sách cuối cùng đó để "mua" các yêu cầu về chỉ số.
// 4. Bảng giá "mua" yêu cầu:
//    - 1 level = 1 điểm.
//    - 1 ATK/DEF/SPD = 1 điểm.
//    - 22 HP = 1 điểm

// --- VÍ DỤ QUY TRÌNH ---
// VÍ DỤ 1: Vật phẩm Hiếm, yêu cầu 2 chỉ số (ATK, DEF)
// - Bước 1: Chọn yêu cầu cấp độ là 18.
// - Bước 2: Ngân sách Yêu cầu cho phẩm chất Hiếm là 70 điểm.
//   - "Mua" level 18 tốn 18 điểm. Ngân sách còn lại: 70 - 18 = 52 điểm.
// - Bước 2.5: Vật phẩm yêu cầu 2 chỉ số -> Dùng toàn bộ 52 điểm.
// - Bước 3: Chia 52 điểm cho 2 yêu cầu: 30 điểm cho ATK, 22 điểm cho DEF.
// - KẾT QUẢ: "Requirements": "level:18,atk:30,def:22"

// VÍ DỤ 2: Vật phẩm Hiếm, lối build thuần khiết, chỉ yêu cầu 1 chỉ số (ATK)
// - Bước 1: Chọn yêu cầu cấp độ là 18.
// - Bước 2: Ngân sách Yêu cầu cho phẩm chất Hiếm là 70 điểm.
//   - "Mua" level 18 tốn 18 điểm. Ngân sách còn lại: 70 - 18 = 52 điểm.
// - Bước 2.5: Vật phẩm chỉ yêu cầu 1 chỉ số -> Dùng 75% ngân sách còn lại: 52 * 0.75 = 39 điểm.
// - Bước 3: Dùng toàn bộ 39 điểm để "mua" ATK.
// - KẾT QUẢ: "Requirements": "level:18,atk:39"
`;

