const buildPassiveAdventureSkillPrompt = (skillIdea) => `
// >>> QUY TẮC GIÁM ĐỊNH KỸ NĂNG PHIÊU LƯU - BỊ ĐỘNG V4.4 (AI BẮT BUỘC TUÂN THỦ) <<<
// =======================================================================
// --- PHẦN A: BỐI CẢNH & NHIỆM VỤ CỦA BẠN ---
// Bạn là một Kỹ Sư Thiết Kế Game bậc thầy, đang tạo chi tiết cho một KỸ NĂNG PHIÊU LƯU có hiệu ứng BỊ ĐỘNG.
// Ý tưởng đầu vào: { Tên: "${skillIdea.name}", Mô tả: "${skillIdea.description}", Phẩm chất: "${skillIdea.rarity}" }

// --- YÊU CẦU ĐẦU RA (JSON) ---
// 1. Dựa vào ý tưởng, hãy sáng tạo ra một tên (Name) và mô tả (description) hấp dẫn.
// 2. Tuân thủ nghiêm ngặt "QUY TRÌNH TƯ DUY & CÂN BẰNG" ở Phần B.
// 3. Tuân thủ "QUY TẮC CẤU TRÚC" ở Phần C.
// 4. Trả về MỘT đối tượng JSON hoàn chỉnh.

// =======================================================================
// --- PHẦN B: QUY TRÌNH TƯ DUY & CÂN BẰNG (CỰC KỲ QUAN TRỌNG) ---
// Ngươi PHẢI thực hiện tuần tự các bước sau.

// B1. PHÂN TÍCH BẢN CHẤT KỸ NĂNG:
//     - Đọc kỹ ý tưởng. Kỹ năng này có "khiếm khuyết" hay "cái giá phải trả" không?
//       - VÍ DỤ "CÓ KHIẾM KHUYẾT": "Chuyên Cần Giao Thương" => Dành nhiều thời gian kiếm tiền, ít tu luyện.
//       - VÍ DỤ "KHÔNG CÓ KHIẾM KHUYẾT": "Bản Năng Giao Thương" => Thiên phú bẩm sinh.

// B2. XÁC ĐỊNH NGÂN SÁCH (EB):
//     - Ngân sách cơ bản: Thường(10), Tốt(20), Hiếm(35), Cực Phẩm(55), Siêu Phẩm(90), Huyền Thoại(130).
//     - NẾU CÓ KHIẾM KHUYẾT: Ngươi ĐƯỢC PHÉP "bán" MỘT hiệu ứng tiêu cực để tăng EB.
//     - NẾU KHÔNG CÓ KHIẾM KHUYẾT: Ngươi TUYỆT ĐỐI KHÔNG được thêm hiệu ứng tiêu cực.

// B3. "MUA" HIỆU ỨNG BẰNG NGÂN SÁCH:
//     - Dùng toàn bộ ngân sách để "mua" các hiệu ứng từ Bảng giá chi tiết dưới đây.
//     - QUAN TRỌNG: Khi tạo mảng "passive_effects", ngươi BẮT BUỘC phải sử dụng chính xác giá trị trong cột 'Tên Kỹ Thuật (type)' cho thuộc tính "type".

//     --- BẢNG GIÁ & TÊN KỸ THUẬT ---
//     | Hiệu ứng                         | Tên Kỹ Thuật (type)                      | Chi phí EB |
//     |-----------------------------------|------------------------------------------|------------|
//     | +1% Giá Bán vật phẩm              | INCREASE_SELL_PRICE_MODIFIER             | 3          |
//     | -1% Giá Mua vật phẩm              | DECREASE_BUY_PRICE_MODIFIER              | 4          |
//     | +1% EXP nhận được                 | INCREASE_EXP_GAIN_MODIFIER               | 5          |
//     | -1% Độ ngẫu nhiên vật phẩm        | REDUCE_BUDGET_RANDOMNESS                 | 7          |
//     | +1% Tỷ lệ Đột phá thành công      | INCREASE_BREAKTHROUGH_CHANCE             | 8          |
//     | +1% Tỷ lệ Giữ lại Nguyên liệu     | INCREASE_MATERIAL_RETENTION_CHANCE       | 4          |
//     | +1% Thời gian Chế tạo            | REDUCE_CRAFTING_TIME                     | 2          |
//     | +1% Tỷ lệ Vô hiệu Debuff Đan dược | DEBUFF_POTION_NEGATION_CHANCE            | 1          |
//     | +1 Ô Kỹ năng trang bị             | ADD_SKILL_SLOT                           | 30         |
//     | +1 Ô Buff Thức ăn                 | ADD_FOOD_BUFF_SLOT                       | 50         |
//     | -1 Lượt hồi Vật phẩm Đa năng      | REDUCE_POTION_COOLDOWN                   | 90         |

// B4. QUY TẮC TỐI ƯU HÓA:
//     - Ưu tiên chủ đề rõ ràng. Không bắt buộc dùng hết 100% ngân sách nếu nó làm loãng chủ đề.

// =======================================================================
// --- PHẦN C: QUY TẮC CẤU TRÚC (NGHIÊM NGẶT) ---
// - Kỹ năng phải có TỐI THIỂU 1 dòng hiệu ứng và TỐI ĐA 3 dòng hiệu ứng.
// - Giá trị (value) của hiệu ứng tiêu cực phải là một số ÂM.

// =======================================================================
// --- PHẦN D: VÍ DỤ HOÀN CHỈNH (KÈM TƯ DUY TỪNG BƯỚC) ---
// Ý tưởng đầu vào: { Name: "Thời Cơ Chớp Nhoáng", description: "Ngươi học được cách nắm bắt thời cơ trong mọi việc, nhưng lại bỏ bê việc tích lũy kinh nghiệm cơ bản.", Rarity: "Cực Phẩm" }

// // BƯỚC 1: PHÂN TÍCH Ý TƯỞNG
// // - Mô tả có cụm từ "nhưng lại bỏ bê việc tích lũy kinh nghiệm".
// // - Kết luận: Kỹ năng này có khiếm khuyết (drawback).

// // BƯỚC 2: TÍNH TOÁN NGÂN SÁCH (EB)
// // - Ngân sách cơ bản cho phẩm chất "Cực Phẩm" là 55 EB.
// // - "Bán" đi hiệu ứng tiêu cực "-10% EXP nhận được" để tăng ngân sách.
// //   - Chi phí của +1% EXP là 5 EB, vậy -10% EXP sẽ hoàn lại 10 * 5 = 50 EB.
// // - TỔNG NGÂN SÁCH MỚI = 55 (cơ sở) + 50 (hoàn lại) = 105 EB.

// // BƯỚC 3: "MUA" CÁC HIỆU ỨNG TÍCH CỰC
// // - Tên "Thời Cơ Chớp Nhoáng" gợi ý đến sự nhanh nhạy, tận dụng cơ hội.
// // - Mua hiệu ứng mạnh nhất phù hợp: "-1 Lượt hồi Vật phẩm Đa năng". Chi phí: 90 EB.
// // - Ngân sách còn lại: 105 - 90 = 15 EB.
// // - Dùng 15 EB còn lại để mua "+% Giá Bán vật phẩm".
// //   - Sức mạnh = 15 EB / 3 EB/% = 5%.
// //   - Chi phí: 15 EB.
// // - Ngân sách đã tiêu hết (105/105).

// // BƯỚC 4: TỔNG HỢP JSON DỰA TRÊN KẾT QUẢ TÍNH TOÁN
/*
{
  "Name": "Thời Cơ Chớp Nhoáng",
  "description": "Ngươi học được cách nắm bắt thời cơ trong mọi việc, nhưng lại bỏ bê việc tích lũy kinh nghiệm cơ bản.",
  "Rarity": "Cực Phẩm",
  "skillType": "adventure",
  "passive_effects": [
    { "type": "INCREASE_EXP_GAIN_MODIFIER", "value": -10 },
    { "type": "REDUCE_POTION_COOLDOWN", "value": 1 },
    { "type": "INCREASE_SELL_PRICE_MODIFIER", "value": 5 }
  ]
}
*/
`;

const buildActiveAdventureSkillPrompt = (skillIdea) => `
// >>> QUY TẮC GIÁM ĐỊNH KỸ NĂNG PHIÊU LƯU - CHỦ ĐỘNG V1.1 (AI BẮT BUỘC TUÂN THỦ) <<<
// =======================================================================
// --- PHẦN A: BỐI CẢNH & NHIỆM VỤ CỦA BẠN ---
// Bạn là một Kỹ Sư Thiết Kế Game bậc thầy, đang tạo chi tiết cho một KỸ NĂNG PHIÊU LƯU có thể KÍCH HOẠT.
// Ý tưởng đầu vào: { Tên: "${skillIdea.name}", Mô tả: "${skillIdea.description}", Phẩm chất: "${skillIdea.rarity}" }

// --- YÊU CẦU ĐẦU RA (JSON) ---
// 1. Dựa vào ý tưởng, hãy sáng tạo ra một tên (Name) và mô tả (description) hấp dẫn cho toàn bộ kỹ năng.
// 2. Sáng tạo ra MỘT hành động chủ động mà người chơi có thể sử dụng.
// 3. Tuân thủ "QUY TẮC CÂN BẰNG" ở Phần B để quyết định thời gian hiệu lực và hồi chiêu.
// 4. Trả về MỘT đối tượng JSON hoàn chỉnh.

// =======================================================================
// --- PHẦN B: QUY TẮC CÂN BẰNG THỜI GIAN (ĐÃ CẬP NHẬT) ---
// - Phẩm chất càng cao, thời gian hiệu lực (duration_hours) càng dài và thời gian hồi chiêu (cooldown_hours) càng ngắn.
// - Ngưỡng đề xuất chi tiết cho từng phẩm chất:
//   - **Thường:** Hiệu lực rất ngắn (1-2 giờ), hồi chiêu cực dài (36-48 giờ).
//   - **Tốt:** Hiệu lực ngắn (2-3 giờ), hồi chiêu dài (24-36 giờ).
//   - **Hiếm:** Hiệu lực vừa phải (3-5 giờ), hồi chiêu trung bình (18-24 giờ).
//   - **Cực Phẩm:** Hiệu lực tốt (4-8 giờ), hồi chiêu khá ngắn (12-18 giờ).
//   - **Siêu Phẩm:** Hiệu lực dài (6-10 giờ), hồi chiêu ngắn (8-12 giờ).
//   - **Huyền Thoại:** Hiệu lực rất dài (8-16 giờ), hồi chiêu rất ngắn (4-8 giờ).

// =======================================================================
// --- PHẦN C: VÍ DỤ HOÀN CHỈNH ---
/*
{
  "Name": "Dược Sư Chi Nhãn",
  "description": "Khai mở linh nhãn, cho phép ngươi dễ dàng tìm thấy các loại linh thảo quý hiếm xung quanh.",
  "Rarity": "Hiếm",
  "skillType": "adventure",
  "active_actions": [
    {
      "action_name": "Khai Mở Linh Nhãn",
      "description": "Trong 4 giờ tới, AI sẽ tăng đáng kể tỉ lệ xuất hiện các sự kiện liên quan đến việc tìm thấy thảo dược.",
      "duration_hours": 4,
      "cooldown_hours": 18
    }
  ]
}
*/
`;

const buildCreateSkillPrompt = (skillIdea, gameSettings) => {
    // Kiểm tra đầu vào an toàn
    if (!skillIdea || !skillIdea.name) {
        console.warn("buildCreateSkillPrompt được gọi với skillIdea không hợp lệ.");
        return "";
    }
    
    const theme = gameSettings?.theme || "Tiên hiệp";

    // --- BỘ LUẬT CÂN BẰNG SP ---
    const balancingRules = `
// =======================================================================
// PHẦN B: HỆ THỐNG CÂN BẰNG "ĐẦU TƯ RỦI RO" V8.0 (AI BẮT BUỘC TUÂN THỦ)
// =======================================================================
// Bạn là một nhà thiết kế game, phải sử dụng hệ thống này để tạo ra một kỹ năng cân bằng.
//
// B1. TÍNH NGÂN SÁCH TỔNG (SP TỔNG):
//   - Ngân sách cơ bản theo Cooldown (CD) (chỉ có kỹ năng basic không được phép có CD trên 4):
//     - CD 0: 15 SP, CD 1: 20 SP, CD 2: 35 SP, CD 3: 55 SP, CD 4: 75 SP, CD 5: 95 SP, CD 6: 115 SP, CD 7: 135 SP
//   - Hệ số nhân: Phẩm chất 'Tốt': x1.1, 'Hiếm': x1.2, 'Cực Phẩm': x1.35, 'Siêu Phẩm': x1.55, 'Huyền Thoại': x1.8, Kỹ năng 'Ultimate': x1.3
//
// B2. QUY TRÌNH TƯ DUY "ĐẦU TƯ RỦI RO" (BẮT BUỘC TUÂN THỦ TUẦN TỰ)
//   1.  **QUYẾT ĐỊNH "SP CỌC":** Từ SP TỔNG, ngươi phải quyết định có nên trích ra một phần (ví dụ: 30%) để làm "SP Cọc". Đây là phần SP ngươi "đặt cược" vào hiệu ứng có điều kiện, thông thường hiệu ứng cọc sẽ liên quan tới hiệu ứng trước đó.
//       - Nếu không muốn có hiệu ứng thưởng, kỹ năng không qua phức tạp thì SP Cọc = 0.
//   2.  **SP CƠ BẢN:** Số SP còn lại sau khi trừ đi SP Cọc. Dùng toàn bộ số SP này để mua các hiệu ứng VÔ ĐIỀU KIỆN từ các bảng giá ở B3 và B4.
//   3.  **CHỌN ĐIỀU KIỆN & TÍNH SP THƯỞNG:** Chọn MỘT điều kiện từ bảng B5. Sau đó tính SP Thưởng theo công thức:
//       - **SP THƯỞNG = SP CỌC * Hệ Số Nhân Thưởng**
//   4.  **MUA HIỆU ỨNG THƯỞNG:** Dùng toàn bộ SP THƯỞNG để mua các hiệu ứng CÓ ĐIỀU KIỆN từ các bảng giá ở B3 và B4. Lưu ý, không phân bổ sát thương scale vượt quá 800% (8.0) dựa trên chỉ số cho đơn mục tiêu trong 1 lượt.
//
// B3. BẢNG GIÁ HIỆU ỨNG TỨC THỜI (Sát thương / Hồi máu / Khiên)
//   A. SỨC MẠNH CƠ BẢN (Giá trị scale_number là số nguyên, ví dụ 150 cho 150%):
//      - ATK: (tấn công)            1 SP cho mỗi 9 scale_number (9%)
//      - MAX_HP:  (sinh lực)        3 SP cho mỗi 1 scale_number (1%)
//      - MISSING_HP: (sinh lực đã mất)     2 SP cho mỗi 1 scale_number (1%)
//      - CURRENT_HP: (sinh lực hiện tại)     2 SP cho mỗi 1 scale_number (1%)
//      - TẠO KHIÊN:        3 SP cho mỗi 1% MAX_HP của người tạo khiên
//   B. THUỘC TÍNH ĐẶC BIỆT (Áp dụng cho TOÀN BỘ hiệu ứng sát thương):
//      - 10% Xuyên giáp (armor_penetration): +5% tổng chi phí của TẤT CẢ các thành phần sát thương.
//      - Sát thương chuẩn (true_damage): x2.5 tổng chi phí.
//      - Không thể né (cannot_be_dodged): +15 SP (cộng thẳng).
//   C. HỆ SỐ NHÂN MỤC TIÊU: Toàn phe địch (x2.0), Toàn phe mình (x1.8).

// B4. BẢNG GIÁ HIỆU ỨNG TRẠNG THÁI (Buff / Debuff / Khống chế)
//   A. HIỆU ỨNG TRẠNG THÁI (Giá cho 1 lượt, 1 mục tiêu):
//      - Buff/Debuff chỉ số CƠ BẢN (ATK/DEF/SPD %): 0.5 SP cho mỗi 1%
//      - Buff/Debuff chỉ số HIẾM (CR/CDMG %):    1.5 SP cho mỗi 1%
//      - DoT/HoT:                                 2 SP cho mỗi 1% MAX_HP mỗi lượt
//      - Khống chế MỀM (SILENCE - Câm Lăng):                 20 SP
//      - Khống chế CỨNG (STUN - Choáng):                   30 SP
//      - Khống chế CỨNG (SLEEP - Ngủ):                  24 SP
//      - Buff đặc biệt (UNDYING - Bất Tử, DAMAGE_IMMUNITY - Miễn Thương): 45 SP
//   B. TIỆN ÍCH: Thanh tẩy (Dispel): 15 SP mỗi debuff.
//   C. HỆ SỐ NHÂN MỤC TIÊU: Toàn phe địch (x2.2), Toàn phe mình (x2.0).

// B5. BẢNG ĐIỀU KIỆN & HỆ SỐ NHÂN THƯỞNG
//   - Cú pháp: conditions: [{ "trigger": "...", "value": ... }]
//   - HỆ SỐ NHÂN:
//     - Nếu sinh lực mục tiêu < 50% (TARGET_HP_BELOW, value: 0.5): x1.3
//     - Nếu sinh lực mục tiêu < 30% (TARGET_HP_BELOW, value: 0.3): x1.6
//     - Nếu sinh lực mục tiêu < 20% (TARGET_HP_BELOW, value: 0.2): x2.2
//     - Nếu sinh lực mục tiêu < 10% (TARGET_HP_BELOW, value: 0.1): x3.0
//     - Nếu mục tiêu bị Khống Chế MỀM (TARGET_HAS_DEBUFF_TYPE, value: "SOFT_CC"): x1.5
//     - Nếu mục tiêu bị Khống Chế CỨNG (TARGET_HAS_DEBUFF_TYPE, value: "CC"): x2.0
`;

    const jsonStructureGuide = `
// =======================================================================
// PHẦN C: TỪ ĐIỂN HOẠT ẢNH (VFX & MOVEMENT) - CỰC KỲ QUAN TRỌNG
// =======================================================================
// Bắt buộc chọn kết hợp 'moveType' và 'vfxType' sao cho logic với mô tả kỹ năng.

// 1. DI CHUYỂN ('moveType'):
// - 'stay': Đứng yên tại chỗ. Thường dùng cho Cung thủ, Pháp sư, Buff, Debuff.
// - 'dash': Lướt nhanh tiếp cận. Dùng cho Đấu sĩ cận chiến.
// - 'dash_through': Lướt xuyên qua người mục tiêu. Cực ngầu cho Sát thủ, Kiếm khách hệ phong/lôi.
// - 'teleport_behind': Biến mất và hiện ra sau lưng. Dùng cho Ninja, Phép thuật không gian.
// - 'jump_strike': Nhảy lên cao rồi giáng xuống. Dùng cho Rìu, Búa, Đại kiếm, Thể thuật nặng.

// 2. HIỆU ỨNG ('vfxType'):
// - 'slash': Nhát chém lưỡi liềm. Dùng cho Kiếm, Đao.
// - 'strike': Cú đâm thẳng. Dùng cho Thương, Kích, Quyền cước.
// - 'projectile': Đạn bay thẳng. Dùng cho Súng, Ám khí tốc độ cao, Quả cầu phép.
// - 'curved_projectile': Đạn bay đường vòng cung. Dùng cho Cung tên, Ném bom, Ném ám khí nặng.
// - 'beam': Tia chưởng lực laser nối liền 2 người. Dùng cho Phép thuật hủy diệt, Kiếm khí cực mạnh.
// - 'falling_object': Vật thể rơi từ trên trời xuống nổ tung. Dùng cho Thiên thạch, Sấm sét giáng xuống.
// - 'ground_eruption': Năng lượng trồi từ dưới mặt đất lên. Dùng cho Gai đất, Cột nước, Cột dung nham.
// - 'explosion' / 'magic_circle': Vụ nổ hoặc vòng tròn phép thuật bùng phát tại chỗ.
// - 'aura_up': Hào quang bốc lên. BẮT BUỘC dùng cho chiêu hồi máu (heal) hoặc Buff có lợi.
// - 'aura_down': Hào quang giáng xuống. Thường dùng cho các chiêu nguyền rủa, Debuff làm suy yếu.

// =======================================================================
// PHẦN D: HƯỚNG DẪN CẤU TRÚC JSON & MASTER SCHEMA
// =======================================================================
// Bạn phải trả về MỘT ĐỐI TƯỢNG JSON DUY NHẤT.

// D1. CẤU TRÚC KỸ NĂNG TỔNG QUÁT:
{
  "skill_name": "string", "skill_description": "string", "technicaldescription": "string",
  "skill_type": "combat", "skill_category": "basic" | "ultimate", "cooldown": "number",
  "effects": [ /* Mảng các đối tượng Hiệu ứng theo Master Schema */ ]
}

// D2. MASTER SCHEMA CHO MỖI HIỆU ỨNG (BẮT BUỘC TUÂN THỦ):
// {
//   "action": {
//     "type": "damage" | "heal" | "apply_status" | "dispel",
//     "target": { "type": "...", "count": X, "hit_count": Y },
//     "visual_effects": {
//         "vfxType": "slash" | "projectile" | "beam" | "explosion" | "magic_circle" | "strike" | "curved_projectile" | "falling_object" | "ground_eruption" | "aura_up" | "aura_down",
//         "moveType": "dash" | "teleport" | "stay" | "teleport_behind" | "dash_through" | "jump_strike",
//         "color": "#ff0000", // BẮT BUỘC trả về mã màu HEX phù hợp với nguyên tố của chiêu (Vd: Băng #00ffff, Độc #800080, Lửa #ff4500, Hồi máu #00ff00)
//         "vfxCount": 1 // Số lượng hiệu ứng hiển thị trên màn hình (độc lập với hit_count sát thương)
//     },
//     "power_components":[
//       { "source_stat": "ATK", "scale_number": 300, "based_on": "caster" }, // Component VÔ ĐIỀU KIỆN (300 tương đương 300%)
//       { 
//         "source_stat": "ATK", 
//         "scale_number": 150, 
//         "based_on": "caster",
//         "conditions":[ { "trigger": "TARGET_HP_BELOW", "value": 0.5 } ] // Component CÓ ĐIỀU KIỆN
//       }
//     ],
//     "special_properties": { "armor_penetration": 10, "true_damage": false, "cannot_be_dodged": true },
//     "status_to_apply": { 
//          "status_id": "STUN", "duration": 1,
//          "stat_modifications":[{ "stat_name": "SPD_PERCENT", "modifier_type": "percentage", "value": -30 }]
//      },
//     "count": 1 // Dùng cho "dispel"
//   }
// }

// --- VÍ DỤ 1: Kỹ năng đánh đổi HP, gây sát thương AOE ---
/*
{
  "skill_name": "Huyết Tế Ma Công",
  "skill_description": "Thiêu đốt sinh mệnh triệu hồi ma trận máu dưới chân mọi kẻ địch.",
  "technicaldescription": "Gây sát thương AOE 36% Max HP bản thân. Nhận 10% Max HP ST chuẩn.",
  "skill_type": "combat", "skill_category": "ultimate", "cooldown": 6,
  "effects":[
    { "action": { "type": "damage", "target": { "type": "all_enemies" }, "visual_effects": { "vfxType": "ground_eruption", "moveType": "stay", "color": "#8b0000", "vfxCount": 1 }, "power_components":[{ "source_stat": "MAX_HP", "scale_number": 36, "based_on": "caster" }] } },
    { "action": { "type": "damage", "target": { "type": "self" }, "power_components":[{ "source_stat": "MAX_HP", "scale_number": 10, "based_on": "caster" }], "special_properties": { "true_damage": true } } }
  ]
}
*/

// --- VÍ DỤ 2: Kỹ năng Đa Đòn Đánh / Sát thủ ---
/*
{
  "skill_name": "Phi Ảnh Liên Hoàn",
  "skill_description": "Lướt xuyên qua đội hình địch, phóng 5 phi đao.",
  "technicaldescription": "Lướt xuyên mục tiêu, phóng 5 phi đao gây 133% Tốc Độ sát thương lên kẻ địch ngẫu nhiên.",
  "skill_type": "combat", "skill_category": "basic", "cooldown": 3,
  "effects":[
    {
      "action": {
        "type": "damage",
        "target": { "type": "random_enemy" },
        "hit_count": 5,
        "visual_effects": { "vfxType": "curved_projectile", "moveType": "dash_through", "color": "#cccccc", "vfxCount": 5 },
        "power_components":[ { "source_stat": "SPD", "scale_number": 133, "based_on": "caster" } ]
      }
    }
  ]
}
*/
`;

    // --- PROMPT TỔNG HỢP GỬI ĐẾN AI ---
    const prompt = `
// =======================================================================
// PHẦN A: YÊU CẦU CHÍNH
// =======================================================================
// BẠN LÀ MỘT NHÀ THIẾT KẾ GAME CHUYÊN NGHIỆP.
// Nhiệm vụ của bạn là biến một Ý TƯỞỞNG kỹ năng thành một ĐỐI TƯỢỢNG JSON KỸ THUẬT hoàn chỉnh, cân bằng và có cấu trúc.

// **DỮ LIỆU ĐẦU VÀO:**
// - Tên Kỹ năng: "${skillIdea.name}"
// - Mô tả Ý tưởng: "${skillIdea.description}"
// - Bối cảnh thế giới: "${theme}"

// **QUY TRÌNH LÀM VIỆC (BẮT BUỘC):**
// 1.  **Phân Tích & Thiết Kế:** Đọc kỹ ý tưởng để hiểu bản chất kỹ năng (tấn công, phòng thủ, buff, debuff, đánh đổi...).
// 2.  **Cân Bằng:** Sử dụng "HỆ THỐNG CÂN BẰNG SP" (Phần B) để quyết định cooldown và các chỉ số sao cho hợp lý.
// 3.  **VFX Hình ảnh:** Chọn moveType và vfxType cực ngầu và phù hợp với mô tả kỹ năng nhất trong Master Schema.
// 4.  **Tạo Mô Tả Chi Tiết:** Viết mô tả văn học ('skill_description') và mô tả cơ chế ('technicaldescription').
// 5.  **Xây Dựng JSON:** Gói tất cả thông tin trên vào một đối tượng JSON duy nhất theo đúng "HƯỚNG DẪN CẤU TRÚC JSON" (Phần C).

// **YÊU CẦU ĐẦU RA:** Trả về một đối tượng JSON duy nhất và hoàn chỉnh.

${balancingRules}

${jsonStructureGuide}
`;

    return prompt;
};

