const STATUS_LIBRARY = {
  // ======================================================
  //              BUFFS (HIỆU ỨNG CÓ LỢI)
  // ======================================================

  /** Miễn nhiễm các hiệu ứng khống chế cứng và mềm (stun, sleep, silence, taunt...). Vẫn nhận debuff giảm chỉ số và DoT. */
  CC_IMMUNITY: {
    id: 'CC_IMMUNITY',
    name: "Miễn Khống Chế",
    type: "buff",
    is_dispellable: true,
    special_flags: ["CROWD_CONTROL_IMMUNITY"]
  },

  /** Không thể chết. HP không thể xuống dưới 1. */
  UNDYING: {
    id: 'UNDYING',
    name: "Bất Tử",
    type: "buff",
    is_dispellable: false, // Thường không thể giải trừ
    special_flags: ["CANNOT_DIE"]
  },

  /** Miễn nhiễm hoàn toàn sát thương. */
  DAMAGE_IMMUNITY: {
    id: 'DAMAGE_IMMUNITY',
    name: "Miễn Thương",
    type: "buff",
    is_dispellable: true,
    special_flags: ["DAMAGE_IMMUNITY_ALL"]
  },
  
  /** Trạng thái đặc biệt: Không hành động, không bị chọn làm mục tiêu, không nhận sát thương. */
  STASIS: {
    id: 'STASIS',
    name: "Ngưng Đọng",
    type: "buff", // Coi là buff vì có tác dụng bảo vệ
    is_dispellable: false,
    special_flags: ["SKIP_TURN", "DAMAGE_IMMUNITY_ALL", "UNTARGETABLE"]
  },

  // ======================================================
  //              DEBUFFS (HIỆU ỨNG BẤT LỢI)
  // ======================================================
  
  // --- CC (Crowd Control) ---

  /** Mất lượt hoàn toàn. DR giảm theo lượt của mục tiêu. */
  STUN: {
    id: 'STUN',
    name: "Choáng",
    type: "debuff",
    duration_logic: "TURN_BASED",
    is_dispellable: true,
    special_flags: ["SKIP_TURN"]
  },

  /** Mất lượt, bị đánh thức khi nhận ST. DR giảm theo round của trận đấu. */
  SLEEP: {
    id: 'SLEEP',
    name: "Ngủ",
    type: "debuff",
    duration_logic: "ROUND_BASED",
    is_dispellable: true,
    special_flags: ["SKIP_TURN"],
    // >>> THAY ĐỔI Ở ĐÂY <<<
    triggered_effects: [{
      trigger: "ON_TAKE_DAMAGE",
      action: { type: "dispel_self", status_to_dispel_id: "SLEEP" }
    }]
  },

  /** Không thể sử dụng kỹ năng Active/Ultimate. Vẫn có thể đánh thường. */
  SILENCE: {
    id: 'SILENCE',
    name: "Câm Lặng",
    type: "debuff",
    duration_logic: "TURN_BASED",
    is_dispellable: true,
    special_flags: ["CANNOT_USE_ACTIVE_SKILLS"]
  },

  /**
   * LƯU Ý CHO CÁC HIỆU ỨNG KHÁC:
   * - Thanh Tẩy (Cleanse): Sẽ được xử lý như một loại hiệu ứng ('dispel_debuffs'), không phải là một trạng thái.
   * - Giảm chỉ số (Stat Debuffs): Sẽ là "Trạng thái Động", do AI tự lắp ráp với thuộc tính 'stat_changes'.
   * - DoT (Burn, Poison...): Sẽ là "Trạng thái Động", do AI tự lắp ráp với thuộc tính 'effects_on_tick'.
   * Điều này mang lại sự linh hoạt tối đa như chúng ta đã bàn.
   */
};


// Helper Functions
const AvatarDisplay = React.memo(({ 
    entity, 
    handleUserUploadAvatar, 
    onAutoGenerate, 
    isPlayerAvatar = false, 
    className = "w-20 h-20", 
    shapeClass = "rounded-md", 
    readOnly = false 
}) => {
    const [localAvatarSrc, setLocalAvatarSrc] = useState(null);
    const [isLoadingAvatar, setIsLoadingAvatar] = useState(true);
    const [inputUrl, setInputUrl] = useState('');
    const [isEditingUrl, setIsEditingUrl] = useState(false);
    
    useEffect(() => {
        let isMounted = true;
        const fetchAvatar = async () => {
            setIsLoadingAvatar(true);
            
            // Ưu tiên 1: Lấy từ IndexedDB của trình duyệt (Nhẹ RAM)
            if (entity.avatarStoredLocally && entity.id) {
                const base64 = await getAvatarFromIndexedDB(entity.id);
                if (isMounted && base64) {
                    setLocalAvatarSrc(base64);
                    setIsLoadingAvatar(false);
                    return;
                }
            }

            // Ưu tiên 2: Dữ liệu base64 trực tiếp (Chỉ dùng khi vừa load file xong chưa kịp tách)
            if (isMounted && entity.avatarBase64) {
                const src = entity.avatarBase64.startsWith('data:image') 
                    ? entity.avatarBase64 
                    : `data:image/jpeg;base64,${entity.avatarBase64}`;
                setLocalAvatarSrc(src);
            }
            // Ưu tiên 3: Ảnh tĩnh từ hệ thống Combat (Base/Idle Model) - Fix lỗi mất ảnh trong trận
            else if (isMounted && entity.images && (entity.images.idle || entity.images.base)) {
                setLocalAvatarSrc(entity.images.idle || entity.images.base);
            }
            // Ưu tiên 4: URL online
            else if (isMounted && entity.avatarUrl && entity.avatarUrl.trim() !== '') {
                setLocalAvatarSrc(entity.avatarUrl);
            }
        };
        fetchAvatar();
        return () => { isMounted = false; };
    }, [entity.id, entity.avatarStoredLocally, entity.avatarUrl, entity.avatarBase64, entity.lastAvatarUpdate, entity.images?.base, entity.images?.idle]);
    
    const displaySrc = localAvatarSrc || "https://placehold.co/80x80/2D3748/718096?text=??";

    return (
        <div className={`${className} relative group flex-shrink-0`}> 
            <div className={`w-full h-full ${shapeClass} object-cover border border-gray-600 flex items-center justify-center bg-gray-700/80 overflow-hidden`}>
                {isLoadingAvatar ? (
                    <div className="w-1/2 h-1/2 border-2 border-t-transparent border-gray-400 rounded-full animate-spin"></div>
                ) : (
                    <img
                        src={displaySrc}
                        alt={entity.Name}
                        className="w-full h-full object-cover"
                        onError={(e) => { e.target.src="https://placehold.co/80x80/2D3748/E0E0E0?text=Lỗi"; }}
                    />
                )}
            </div>

            {!readOnly && (
                <>
                    <button
                        onClick={(e) => { e.stopPropagation(); setIsEditingUrl(true); }}
                        className="absolute -top-2 -right-2 bg-gray-800 border border-gray-500 rounded-full p-1 text-gray-300 hover:text-white hover:bg-purple-600 shadow-md z-10 opacity-0 group-hover:opacity-100 transition-opacity"
                        title="Nhập URL ảnh"
                    >
                        <PencilIcon className="w-3 h-3" />
                    </button>

                    <button
                        onClick={(e) => { e.stopPropagation(); onAutoGenerate && onAutoGenerate(entity); }}
                        className="absolute -bottom-2 -right-2 bg-gray-800 border border-gray-500 rounded-full p-1 text-yellow-400 hover:text-white hover:bg-yellow-600 shadow-md z-10 opacity-0 group-hover:opacity-100 transition-opacity"
                        title="AI Vẽ Chân Dung"
                    >
                        <SparklesIcon className="w-3 h-3" />
                    </button>
                </>
            )}

            {isEditingUrl && (
                <div className="absolute top-0 left-0 w-64 bg-gray-900 border border-purple-600 rounded-lg shadow-xl p-3 z-50 translate-x-10">
                    <p className="text-xs text-gray-300 mb-2">Nhập URL ảnh:</p>
                    <input
                        type="url"
                        value={inputUrl}
                        onChange={(e) => setInputUrl(e.target.value)}
                        className="w-full text-xs p-2 bg-gray-800 border border-gray-700 rounded-md text-white mb-2"
                        autoFocus
                        onClick={(e) => e.stopPropagation()}
                    />
                    <div className="flex justify-end gap-2">
                        <button onClick={(e) => {
                            e.stopPropagation();
                            if(inputUrl) handleUserUploadAvatar(isPlayerAvatar ? inputUrl : entity.id, inputUrl);
                            setIsEditingUrl(false);
                            setInputUrl('');
                        }} className="bg-purple-600 text-white text-xs px-2 py-1 rounded">Lưu</button>
                        <button onClick={(e) => { e.stopPropagation(); setIsEditingUrl(false); }} className="bg-gray-600 text-white text-xs px-2 py-1 rounded">Hủy</button>
                    </div>
                </div>
            )}
        </div>
    );
});

