const [showSkillManagementModal, setShowSkillManagementModal] = useState(false);const handleAllocateAp = (pointsToAllocate, characterId = 'player') => {
    setknowledge(prevKnowledge => {
        const newKnowledge = JSON.parse(JSON.stringify(prevKnowledge));
        const charIndex = newKnowledge.characters.findIndex(c => c.id === characterId);

        if (charIndex === -1) return prevKnowledge;
        let character = newKnowledge.characters[charIndex];

        const totalPointsToSpend = Object.values(pointsToAllocate).reduce((sum, val) => sum + val, 0);

        if (!character.ap || character.ap < totalPointsToSpend) {
            setTimeout(() => { 
                setModalMessage({ 
                    show: true, 
                    title: "Không Đủ Điểm", 
                    content: `Ngươi cần ${totalPointsToSpend} điểm tiềm năng nhưng chỉ có ${character.ap || 0} điểm.`, 
                    type: "error" 
                });
            }, 0);
            return prevKnowledge;
        }

        character.ap -= totalPointsToSpend;

        for (const statKey in pointsToAllocate) {
            const points = pointsToAllocate[statKey];
            if (points > 0) {
                if (!character.allocatedPoints) {
                    character.allocatedPoints = { hp: 0, atk: 0, def: 0, spd: 0 };
                }
                // *** THAY ĐỔI CỐT LÕI: CHỈ CẬP NHẬT `allocatedPoints` ***
                character.allocatedPoints[statKey] = (character.allocatedPoints[statKey] || 0) + points;
                
                // Dòng cập nhật baseStats đã được XÓA BỎ
            }
        }

        newKnowledge.characters[charIndex] = calculateFinalStats(character);
        return newKnowledge;
    });
};


const autoAllocateNpcAp = (npc) => {
        let pointsToSpend = npc.ap || 0;
        if (pointsToSpend === 0) return npc; // Không có điểm để cộng, trả về ngay
    
        // Tạo bản sao để làm việc
        const workingNpc = { ...npc };
        
        // Định nghĩa các khuôn mẫu build dựa trên vai trò
        const buildTemplates = {
            'Tanker':     { hp: 4, def: 4, atk: 1, spd: 0 },
            'DPS':        { hp: 2, def: 1, atk: 4, spd: 1 },
            'Assassin':   { hp: 1, def: 1, atk: 3, spd: 3 },
            'Support':    { hp: 3, def: 2, atk: 1, spd: 2 },
            'Controller': { hp: 2, def: 3, atk: 1, spd: 2 },
            'Default':    { hp: 2, def: 2, atk: 2, spd: 2 } // Mặc định nếu không có Role
        };

        const template = buildTemplates[npc.Role] || buildTemplates['Default'];
        const totalWeight = Object.values(template).reduce((sum, weight) => sum + weight, 0);

        if (totalWeight > 0) {
            // Phân phối điểm dựa trên tỷ lệ của khuôn mẫu
            for (const statKey in template) {
                const weight = template[statKey];
                const pointsForStat = Math.floor((weight / totalWeight) * pointsToSpend);
                
                // Lấy ra tỷ lệ chuyển đổi từ hằng số
                const increaseAmount = AP_CONVERSION_RATES[statKey] * pointsForStat;

                // Cập nhật chỉ số GỐC
                const baseStatKey = `base${statKey.charAt(0).toUpperCase() + statKey.slice(1)}`;
                if (workingNpc.hasOwnProperty(baseStatKey) && increaseAmount) {
                    workingNpc[baseStatKey] += increaseAmount;
                }
            }
        }
        
        // Sau khi cộng xong, reset AP của NPC về 0
        workingNpc.ap = 0;
        
        return workingNpc;
    };


const updateOrCreateInArray = (array, newItem, keyField = 'Name') => {
    // Luôn kiểm tra để đảm bảo đầu vào hợp lệ
    if (!array || !newItem) {
        return;
    }

    // --- LOGIC MỚI: Xử lý key tên không nhất quán ---
    // Chuẩn hóa tên của newItem về một dạng duy nhất để so sánh
    const newItemNameLower = (newItem[keyField] || newItem[keyField.toLowerCase()] || '').toLowerCase();
    
    if (!newItemNameLower) {
        // Nếu item mới không có tên, không làm gì cả
        return;
    }

    // Tìm vị trí của item đã có trong mảng, so sánh không phân biệt hoa thường và key
    const existingIndex = array.findIndex(item => {
        if (!item) return false;
        // Chuẩn hóa tên của item hiện có trong mảng
        const existingItemNameLower = (item[keyField] || item[keyField.toLowerCase()] || '').toLowerCase();
        return existingItemNameLower === newItemNameLower;
    });
    // --- KẾT THÚC LOGIC MỚI ---

    if (existingIndex > -1) {
        // Nếu đã tồn tại, hợp nhất (merge) đối tượng cũ với các thuộc tính mới.
        // Điều này sẽ cập nhật entry cũ với các thông tin mới nhất từ AI.
        array[existingIndex] = { ...array[existingIndex], ...newItem };
    } else if (newItem) {
        // Nếu chưa tồn tại, thêm đối tượng mới vào mảng.
        // Gán một ID ngẫu nhiên nếu nó chưa có.
        array.push({ id: crypto.randomUUID(), ...newItem });
    }
};


    const max_EXP_GAIN_PER_TURN = 100000;

    const updateCharacterStats = (character, statsToChange) => {
    // Luôn làm việc trên một bản sao
    const newCharacter = { ...character };
    
    for (const key in statsToChange) {
        const value = parseFloat(statsToChange[key]);
        if (!isNaN(value)) {
            // Đảm bảo thuộc tính tồn tại trước khi cộng
            newCharacter[key] = (newCharacter[key] || 0) + value;
        }
    }
    return newCharacter;
};

const fetchInitialItemDetails = async (itemIdeaWithRarity, effectiveApiKey) => {
    // (Prompt và schema không đổi)
    const prompt = `
        Bạn là một chuyên gia giám định vật phẩm game cực kỳ logic và tuân thủ quy tắc. Dựa vào thông tin dưới đây, hãy trả về một đối tượng JSON.

        --- THÔNG TIN VẬT PHẨM ĐẦU VÀO ---
        - Tên: "${itemIdeaWithRarity.name}"
        - Mô tả gốc: "${itemIdeaWithRarity.description}"
        - Phẩm chất ĐÃ ĐƯỢC ẤN ĐỊNH: "${itemIdeaWithRarity.rarity}"

        --- CHECKLIST NHIỆM VỤ (BẮT BUỘC THỰC HIỆN TUẦN TỰ) ---

        **NHIỆM VỤ 1:    Ngươi phải kiểm tra ý tưởng vật phẩm theo đúng thứ tự các câu hỏi dưới đây. Ngay khi tìm thấy một quy tắc ĐÚNG, hãy chọn 'category' tương ứng và dừng lại.
        1. Chức năng có phải là LƯU TRỮ, CHỨA ĐỰNG không?
           - Nếu mục đích chính là **tăng sức chứa hành trang**, bất kể hình dạng (nhẫn, túi, hồ lô...), 'category' **BẮT BUỘC** phải là **"Trữ vật"**.
        2. Chức năng có phải là DI CHUYỂN không?
           - Nếu người chơi dùng nó để **cưỡi hoặc điều khiển để di chuyển** (ngựa, phi kiếm, thuyền bay...), 'category' **BẮT BUỘC** phải là **"Phương tiện"**.
        3. Chức năng có phải là HỌC TẬP vĩnh viễn không?
           - Nếu người chơi dùng nó để **học một năng lực mới vĩnh viễn**, 'category' **BẮT BUỘC** phải là **"Sách kỹ năng"**.
        4. Nó có phải là THỨ KỲ LẠ, ĐỘC ĐÁO đính/đeo/cấy ghép lên cơ thể không?
           - Nếu nó được **gắn/cấy/ghép vào cơ thể**, hoặc là một vật thể sống cộng sinh, hoặc có hiệu ứng phá vỡ quy tắc nhưng không phải trang bị thông thường (vũ khí, giáp, phụ kiện), 'category' **BẮT BUỘC** phải là **"Dị thường"**.
           - Ví dụ: Một con mắt ma thuật thay thế mắt thường, một trái tim quỷ, một hình xăm sống, một con cổ trùng...
        5. Nó có phải là TRANG BỊ thông thường không?
           - Nếu nó được **mặc hoặc cầm** để tăng chỉ số chiến đấu trực tiếp, hãy chọn 'category' phù hợp: 'Vũ khí', 'Thân', 'Đầu', 'Chân', 'Phụ kiện'.
        6. Nó có phải là VẬT PHẨM TIÊU HAO không?
           - Nó có phải thức ăn không? Như thịt, trái cây, bánh kẹo,... -> **"Thực phẩm"**.
           - Dùng để viên đan, thuốc, huyết thanh chỉ được dùng lên bản thân -> **"Đan dược"**.
           - Dùng để tạo khiên hồi phục lên đồng minh, tấn công / gây hiệu ứng lên kẻ địch như mìn, bùa chú, phi tiêu, phù,... -> **"Đa năng"**.
        7. Nếu không thuộc các loại trên, hãy xét các loại sau:**
           - Dùng để **hoàn thành nhiệm vụ, có giá trị cốt truyện** -> **"Tín vật"**.
           - Dùng làm **nguyên liệu chế tạo** -> **"Nguyên liệu"**.
           - Nếu không có công dụng rõ ràng -> **"Tạp vật"**.

        **NHIỆM VỤ 2: Tinh chỉnh Mô tả (description)**
        *   Sau khi đã xác định được 'category', hãy đọc lại Mô tả gốc và so sánh nó với Phẩm chất đã được ấn định.
        *   NẾU Mô tả gốc không phù hợp (quá mạnh hoặc quá yếu so với phẩm chất), BẮT BUỘC phải viết lại một mô tả mới cho hợp lý, nhưng vẫn giữ được tinh thần của ý tưởng gốc.
        *   NẾU Mô tả gốc đã phù hợp, hãy sử dụng lại nó.

        --- VÍ DỤ GIÁM ĐỊNH MẪU (BẮT BUỘC HỌC THEO) ---
        // Đầu vào: { name: "Áo Choàng Tinh Không", description: "Chiếc áo choàng dệt từ tinh tú, ban cho người mặc khả năng ẩn mình hoàn hảo và kháng phép tuyệt đối.", rarity: "Tốt" }
        // Phân tích của AI:
        // 1. Xác định category: Đây là trang bị mặc trên người -> "Thân".
        // 2. Tinh chỉnh mô tả: Mô tả "hoàn hảo" và "tuyệt đối" quá mạnh so với phẩm chất "Tốt". Cần hạ cấp.
        // Kết quả JSON trả về:
        /*
        {
          "category": "Thân",
          "description": "Chiếc áo choàng có màu xanh thẫm lấp lánh như bầu trời đêm, giúp người mặc dễ dàng hòa lẫn vào bóng tối và có khả năng kháng nhẹ các loại chú thuật cấp thấp."
        }
        */

        --- DANH SÁCH 'category' HỢP LỆ ---
        [${ITEM_TYPES.join(', ')}]
        
        --- YÊU CẦU ĐẦU RA ---
        CHỈ trả về một đối tượng JSON duy nhất chứa 2 thuộc tính: 'category' và 'description'.
    `;
    const schema = { type: "OBJECT", properties: { category: { type: "STRING", enum: ITEM_TYPES }, description: { type: "STRING" } }, required: ["category", "description"], };
    const payload = { contents: [{ role: "user", parts: [{ text: prompt }] }], generationConfig: { response_mime_type: "application/json", response_schema: schema } };
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

    try {
        const jsonText = await fetchWithRetries(apiUrl, payload);
        return JSON.parse(jsonText);
    } catch (error) {
        console.error(`Lỗi trong fetchInitialItemDetails sau khi thử lại nhiều lần cho '${itemIdeaWithRarity.name}':`, error);
        return null;
    }
};
const fetchNpcDetailsFromAI = async (npcBasicInfo, gameSettings, effectiveApiKey, playerLevel) => {
    const prompt = `
        VAI TRÒ: Ngươi là một Bậc Thầy Tướng Thuật và Người Kể Chuyện. 
        BỐI CẢNH GAME: Thế giới "${gameSettings.theme}", Bối cảnh: "${gameSettings.setting}".
        Cấp độ hiện tại của Nhân vật chính: ${playerLevel}.

        THÔNG TIN NPC SƠ BỘ:
        - Tên: "${npcBasicInfo.Name || npcBasicInfo.name}"
        - Ghi chú hiện tại: "${npcBasicInfo.description || 'Không có'}"

        NHIỆM VỤ: NPC này vừa trở thành một nhân vật quan trọng có tương tác với người chơi. Hãy "Giám định" và thổi hồn cho NPC này bằng cách tạo ra một hồ sơ chi tiết.
        
        YÊU CẦU DỮ LIỆU:
        1. "Gender": Xác định giới tính (Nam, Nữ, Khác, Không xác định) dựa vào tên và bối cảnh.
        2. "Role": Vai trò/Thân phận thực sự của NPC này trong thế giới.
        3. "Appearance": Mô tả CHI TIẾT ngoại hình, trang phục, khí chất.
        4. "Backstory": Tiểu sử, quá khứ, động lực hoặc bí mật của NPC này.
        5. "Personality": Tính cách đặc trưng (VD: Xảo quyệt, Nóng nảy, Trượng nghĩa...).
        6. "Stance": Thái độ với nhân vật chính.
        7. "level": Một cấp độ hợp lý dựa theo thân phận.

        CHỈ TRẢ VỀ JSON THEO ĐÚNG SCHEMA KHÔNG KÈM GIẢI THÍCH.
    `;

    const schema = {
        type: "OBJECT",
        properties: {
            Gender: { type: "STRING", enum: ["Nam", "Nữ", "Khác", "Không xác định"] },
            Role: { type: "STRING" },
            Appearance: { type: "STRING" },
            Backstory: { type: "STRING" },
            Personality: { type: "STRING" },
            Stance: { type: "STRING" },
            level: { type: "NUMBER" }
        },
        required: ["Gender", "Role", "Appearance", "Backstory", "Personality", "Stance", "level"]
    };

    const payload = {
        contents: [{ role: "user", parts: [{ text: prompt }] }],
        generationConfig: { response_mime_type: "application/json", response_schema: schema }
    };
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

    try {
        const jsonText = await fetchWithRetries(apiUrl, payload);
        return JSON.parse(jsonText);
    } catch (error) {
        console.error(`Lỗi khi giám định chi tiết NPC '${npcBasicInfo.Name}':`, error);
        return null;
    }
};
const fetchInitialSkillDetails = async (skillIdea, effectiveApiKey, storyHistory) => {
    // (Prompt và schema không đổi)
    const prompt = `
        Bạn là một Kỹ Sư Phân Loại Kỹ Năng game cực kỳ logic và chi tiết. Dựa vào thông tin dưới đây, hãy trả về một đối tượng JSON.

        --- THÔNG TIN CẦN GIÁM ĐỊNH ---
        - Tên: "${skillIdea.name}"
        - Mô tả: "${skillIdea.description}"
        - Phẩm chất HỆ THỐNG ĐÃ ẤN ĐỊNH: "${skillIdea.rarity}" 

        --- QUY TRÌNH PHÂN LOẠI TUẦN TỰ (BẮT BUỘC THỰC HIỆN) ---

        1.  **BƯỚC 1: PHÂN TÍCH CHỨC NĂNG CỐT LÕI**
            *   Đọc kỹ "Mô tả" để hiểu chức năng chính của kỹ năng.
            *   Nó dùng TRONG hay NGOÀI trận đấu?
            *   Nó là một hiệu ứng bị động hay một hành động có thể kích hoạt?
            *   Nó là một chiêu thức thông thường hay một tuyệt chiêu thay đổi cục diện?

        2.  **BƯỚC 2: XÁC ĐỊNH LOẠI CHÍNH ('skillType')**
            *   Nếu chức năng chính dùng **TRONG** trận đấu -> 'skillType' là **"combat"**.
            *   Nếu chức năng chính dùng **NGOÀI** trận đấu -> 'skillType' là **"adventure"**.

        3.  **BƯỚC 3: XÁC ĐỊNH PHÂN LOẠI PHỤ ('skillCategory')**
            *   **NẾU** 'skillType' là "combat": Dựa vào mô tả, nó là chiêu thức mạnh, thay đổi cục diện không? -> **"ultimate"**. Nếu không -> **"basic"**.
            *   **NẾU** 'skillType' là "adventure": Hiệu ứng có phải luôn tồn tại mà không cần kích hoạt không? -> **"passive"**. Hay nó là một hành động có thể được kích hoạt? -> **"active"**.

        --- DANH SÁCH GIÁ TRỊ HỢP LỆ ---
        - skillType: ["combat", "adventure"]
        - skillCategory: ["basic", "ultimate", "passive", "active"]

        --- YÊU CẦU ĐẦU RA ---
        CHỈ trả về một đối tượng JSON duy nhất chứa 2 thuộc tính: 'skillType' và 'skillCategory'.
    `;
    const schema = { type: "OBJECT", properties: { skillType: { type: "STRING", enum: ["combat", "adventure"] }, skillCategory: { type: "STRING", enum: ["basic", "ultimate", "passive", "active"] } }, required: ["skillType", "skillCategory"], };
    const payload = { contents: [{ role: "user", parts: [{ text: prompt }] }], generationConfig: { response_mime_type: "application/json", response_schema: schema } };
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

    try {
        const jsonText = await fetchWithRetries(apiUrl, payload);
        const preliminaryDetails = JSON.parse(jsonText);
        // (Logic xử lý fallback không đổi)
        if (preliminaryDetails.type && !preliminaryDetails.skillType) { preliminaryDetails.skillType = preliminaryDetails.type; delete preliminaryDetails.type; }
        if (preliminaryDetails.skillType === 'adventure' && !preliminaryDetails.skillCategory) { preliminaryDetails.skillCategory = 'passive'; }
        if (preliminaryDetails.skillType === 'combat' && !preliminaryDetails.skillCategory) { preliminaryDetails.skillCategory = 'basic'; }
        return preliminaryDetails;
    } catch (error) {
        console.error(`Lỗi khi giám định sơ bộ kỹ năng '${skillIdea.name}' sau nhiều lần thử:`, error);
        throw error;
    }
};

const updatePlayerInventory = (currentKnowledge, itemId, quantityToRemove) => {
    // Luôn làm việc trên một bản sao sâu để đảm bảo tính bất biến
    const newKnowledge = JSON.parse(JSON.stringify(currentKnowledge));
    const playerIndex = newKnowledge.characters.findIndex(c => c.isPlayer);

    if (playerIndex === -1) {
        console.error("updatePlayerInventory: Không tìm thấy người chơi.");
        return currentKnowledge; // Trả về state gốc nếu không tìm thấy
    }

    const player = newKnowledge.characters[playerIndex];
    if (!player.inventory) {
        player.inventory = [];
        return newKnowledge;
    }

    const itemIndex = player.inventory.findIndex(invItem => invItem.id === itemId);

    if (itemIndex > -1) {
        const inventoryItem = player.inventory[itemIndex];
        
        // Nếu vật phẩm có số lượng, thì trừ đi
        if (inventoryItem.quantity && inventoryItem.quantity > 1) {
            inventoryItem.quantity -= quantityToRemove;
            
            // Nếu số lượng sau khi trừ nhỏ hơn hoặc bằng 0, xóa nó đi
            if (inventoryItem.quantity <= 0) {
                player.inventory.splice(itemIndex, 1);
            }
        } else {
            // Nếu vật phẩm không có số lượng hoặc số lượng là 1, xóa nó đi
            player.inventory.splice(itemIndex, 1);
        }
    } else {
        console.warn(`updatePlayerInventory: Không tìm thấy vật phẩm với ID ${itemId} trong hành trang.`);
    }

    return newKnowledge;
};
const handleConfirmSell = () => {
    // Sử dụng closure để lấy state mới nhất tại thời điểm hàm được gọi
    const { playerOffer, sellMultiplier, itemSpecificSellBonuses } = activeTrade;

    if (!playerOffer || playerOffer.length === 0) {
        // Không cần thông báo lỗi ở đây vì đây là trường hợp gần như không thể xảy ra
        console.warn("handleConfirmSell được gọi nhưng không có vật phẩm nào trên bàn đàm phán.");
        return;
    }

    // Tính toán giá trị bán cuối cùng
    const { finalSellValue } = calculateFinalSellValue(playerOffer, sellMultiplier, itemSpecificSellBonuses, gameSettings.difficulty, playerCharacter);

    // Cập nhật state knowledge bằng cách sử dụng function update
    setknowledge(prevKnowledge => {
        const newKnowledge = JSON.parse(JSON.stringify(prevKnowledge));
        const playerIndex = newKnowledge.characters.findIndex(c => c.isPlayer);
        
        if (playerIndex > -1) {
            // Cộng tiền cho người chơi
            newKnowledge.characters[playerIndex].currency = (newKnowledge.characters[playerIndex].currency || 0) + finalSellValue;

            // Xóa các vật phẩm đã bán khỏi hành trang
            playerOffer.forEach(offerItem => {
                const itemIndex = newKnowledge.characters[playerIndex].inventory.findIndex(invItem => invItem.id === offerItem.id);
                if (itemIndex > -1) {
                    const invItem = newKnowledge.characters[playerIndex].inventory[itemIndex];
                    if (invItem.quantity > offerItem.quantity) {
                        invItem.quantity -= offerItem.quantity;
                    } else {
                        newKnowledge.characters[playerIndex].inventory.splice(itemIndex, 1);
                    }
                }
            });
        }
        return newKnowledge;
    });

    // Dọn dẹp bàn đàm phán
    setActiveTrade(prev => ({
        ...prev,
        playerOffer: [],
        sellMultiplier: 0,
        itemSpecificSellBonuses: {},
    }));
    
    // Hiển thị thông báo thành công
    setModalMessage({
        show: true,
        title: "Bán Thành Công!",
        content: `Ngươi đã bán các vật phẩm và nhận được ${finalSellValue} ${gameSettings.currencyName || 'Vàng'}.`,
        type: 'success'
    });
};
// Tìm đến hàm bên dưới
const createAndFinalizeOfferedItem = async (itemIdea, trader, player, gameSettings) => {
    try {
        // Bước a: Xác định phẩm chất dựa trên cấp độ của thương nhân
        const rarity = getFinalRarityByLevel(trader.level || player?.level || 1);
        const itemIdeaWithRarity = { ...itemIdea, rarity };
        const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";

        // Bước b: Giám định sơ bộ để lấy Category
        const preliminaryDetails = await fetchInitialItemDetails(itemIdeaWithRarity, effectiveApiKey);
        if (!preliminaryDetails || !preliminaryDetails.category) {
            console.warn(`Không thể xác định category cho "${itemIdea.name}", bỏ qua vật phẩm này.`);
            return null;
        }

        // Bước c: Tính toán ngân sách chính xác
        const budgetDetails = { category: preliminaryDetails.category, rarity: rarity };
        const balancingBudget = calculateBalancingBudget(budgetDetails, player, gameSettings.difficulty);

        // Bước d: Giám định chi tiết để lấy toàn bộ thông tin
        const detailedIdeaForAI = {
            name: itemIdea.name,
            description: preliminaryDetails.description,
            category: preliminaryDetails.category,
            rarity: rarity,
            value: balancingBudget
        };
        const itemFromAI = await fetchItemDetailsFromAI(detailedIdeaForAI, effectiveApiKey);
        if (!itemFromAI) {
            console.warn(`Không thể tạo chi tiết cho "${itemIdea.name}", bỏ qua vật phẩm này.`);
            return null;
        }

        // Trả về vật phẩm hoàn chỉnh
        return { ...itemFromAI, id: crypto.randomUUID(), Value: balancingBudget };

    } catch (error) {
        console.error(`Lỗi trong quá trình tạo vật phẩm được đề nghị "${itemIdea.name}":`, error);
        return null;
    }
};

const fetchWithRetries = async (apiUrl, payload, onRetry = null, maxRetries = 2, retryDelay = 1000) => {
    let lastError = null;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
        try {
            const response = await fetch(apiUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });

            if (!response.ok) {
                const errorText = await response.text();
                if (response.status === 401 || response.status === 429) { 
                    throw new Error(`Lỗi Rate Limit/Xác thực (${response.status}). Có quá nhiều yêu cầu được gửi đi cùng lúc.`);
                }
                throw new Error(`API trả về lỗi HTTP ${response.status}: ${errorText}`);
            }

            const responseText = await response.text();
            if (!responseText) {
                throw new Error("Phản hồi từ API rỗng.");
            }
            
            const result = JSON.parse(responseText);
            const blockReason = result.promptFeedback?.blockReason;
            if (blockReason) {
                throw new Error(`AI Safety Filter: ${blockReason}`);
            }
            
            const jsonText = result.candidates?.[0]?.content?.parts?.[0]?.text;
            if (!jsonText || jsonText.trim() === '') {
                throw new Error("Nội dung text trong phản hồi của AI rỗng.");
            }
            
            return jsonText;

        } catch (error) {
            lastError = error;
            console.warn(`Lần gọi API thứ ${attempt + 1} thất bại:`, error.message);

            if (attempt < maxRetries) {
                if (onRetry) {
                    onRetry(attempt + 1, maxRetries);
                }
                await new Promise(resolve => setTimeout(resolve, retryDelay * (attempt + 1)));
            }
        }
    }
    throw new Error(`AI không phản hồi hợp lệ sau ${maxRetries + 1} lần thử. Lỗi cuối cùng: ${lastError.message}`);
};

const handleConfirmBuy = (itemToBuy, finalPrice) => {
    // --- BƯỚC 1: KIỂM TRA ĐIỀU KIỆN ---
    if (!itemToBuy) return;
    const player = knowledge.characters.find(c => c.isPlayer);
    if (!player || (player.currency || 0) < finalPrice) {
        setModalMessage({
            show: true,
            title: "Không Đủ Tiền",
            content: `Ngươi không đủ ${gameSettings.currencyName} để mua "${itemToBuy.Name}".`,
            type: 'error'
        });
        return;
    }

    // --- BƯỚC 2: CẬP NHẬT STATE `knowledge` ---
    setknowledge(prev => {
        const newKnowledge = JSON.parse(JSON.stringify(prev));
        const playerIndex = newKnowledge.characters.findIndex(c => c.isPlayer);
        const traderIndex = newKnowledge.characters.findIndex(c => c.id === activeTrade.trader.id);

        if (playerIndex === -1 || traderIndex === -1) {
            console.error("Lỗi mua hàng: không tìm thấy người chơi hoặc thương nhân trong knowledge.characters");
            return prev;
        }
        
        let playerToUpdate = newKnowledge.characters[playerIndex];
        let traderToUpdate = newKnowledge.characters[traderIndex];

        // Trừ tiền của người chơi, cộng tiền cho NPC
        playerToUpdate.currency -= finalPrice;
        traderToUpdate.currency = (traderToUpdate.currency || 0) + finalPrice;

        // Thêm vật phẩm vào hành trang người chơi
        if (!playerToUpdate.inventory) playerToUpdate.inventory = [];
        playerToUpdate.inventory.push({ ...itemToBuy, id: crypto.randomUUID() });
        
        // Cập nhật lại các đối tượng trong mảng
        newKnowledge.characters[playerIndex] = playerToUpdate;
        newKnowledge.characters[traderIndex] = traderToUpdate;
        
        return newKnowledge;
    });

    // --- BƯỚC 3: DỌN DẸP GIAO DIỆN & THÔNG BÁO ---
    setActiveTrade(prev => ({
        ...prev,
        npcOffer: null, // Dọn dẹp bàn mua
        itemSpecificBuyBonuses: {}, 
        traderWares: (prev.traderWares || []).filter(ware => ware.id !== itemToBuy.id)
    }));

    setModalMessage({
        show: true,
        title: "Mua Thành Công!",
        content: `Ngươi đã mua "${itemToBuy.Name}" với giá ${finalPrice} ${gameSettings.currencyName}.`,
        type: 'success'
    });
};

// 2. Tạo hàm startTrade (Hàm mới)
const startTrade = (traderObject, knowledgeForPrompt) => {
    // --- BƯỚC 1: XÁC THỰC ĐẦU VÀO ---
    if (!traderObject || !traderObject.Name) {
        console.error("Lỗi bắt đầu giao dịch: Đối tượng trader không hợp lệ hoặc không có tên.");
        setModalMessage({ 
            show: true, 
            title: "Lỗi Hệ Thống", 
            content: "Không thể bắt đầu giao dịch vì thiếu thông tin về người bán.", 
            type: 'error' 
        });
        return; 
    }

    // --- BƯỚC 2: THIẾT LẬP STATE CHO CHẾ ĐỘ GIAO DỊCH ---
    
    // 1. Chuyển game sang chế độ TRADE
    setGameMode('TRADE');

    // 2. Thiết lập thông tin giao dịch ban đầu VỚI CẤU TRÚC STATE ĐÚNG
    setActiveTrade({ 
        trader: traderObject, 
        playerOffer: [], 
        npcOffer: null,
        offerType: 'sell',
        // --- CÁC THUỘC TÍNH ĐÃ ĐƯỢC CẬP NHẬT ĐẦY ĐỦ ---
        sellMultiplier: 0,
        buyMultiplier: 1,
        itemSpecificSellBonuses: {}, // << ĐÂY LÀ DÒNG QUAN TRỌNG NHẤT BỊ THIẾU
    });
    
    // 3. Hiển thị modal giao dịch
    setShowTradeModal(true);

    // 4. Tạo một thông báo hệ thống để người chơi biết chế độ đã thay đổi
    const systemEntry = { 
        id: crypto.randomUUID(), 
        type: 'system', 
        content: `--- BẮT ĐẦU GIAO DỊCH VỚI ${traderObject.Name} ---` 
    };
    setStoryHistory(prev => [...prev, systemEntry]);
    
    // 5. Xóa các lựa chọn cũ để chuẩn bị cho các lựa chọn giao dịch mới
    setChoices([]);

    // --- BƯỚC 3: GỌI AI ĐỂ BẮT ĐẦU CUỘC HỘI THOẠI ---
    
    // 3.1 Xây dựng prompt để AI tạo ra lời thoại và các lựa chọn ban đầu
    const tradeStartPrompt = `
        **BỐI CẢNH:** Ngươi vừa bắt đầu một cuộc giao dịch với ${traderObject.Name}, một nhân vật có vai trò là "${traderObject.Role || 'Không rõ'}" và tính cách "${traderObject.Personality || 'Bí ẩn'}". Hiện tại trên bàn đàm phán chưa có vật phẩm nào.
        
        **YÊU CẦU CHO AI:**
        1.  **Viết lời thoại mở đầu:** Viết một đoạn ngắn mô tả thái độ và lời nói đầu tiên của ${traderObject.Name} khi bắt đầu giao dịch. (Ví dụ: hắn kiên nhẫn chờ đợi, hoặc hắn hối thúc ngươi, hoặc hắn tỏ ra thân thiện...).
        2.  **Tạo các lựa chọn thương lượng:**
            *   Thêm 4 lựa chọn cố định: "Hỏi đối phương có bán vật phẩm gì không?", "Hỏi đối phương có muốn mua các vật phẩm của mình không?", "Kết thúc cuộc giao dịch và hỏi thăm về vấn đề khác.", và "Kết thúc cuộc trò chuyện và rời đi."
        3.  **Định dạng:** Đảm bảo tổng cộng có chính xác 4 lựa chọn, mỗi lựa chọn trên một dòng và có đánh số.
    `;
    
    // 3.2 Gọi API, truyền vào knowledge mới nhất để AI có đầy đủ bối cảnh
    callGeminiAPI(tradeStartPrompt, false, {}, knowledgeForPrompt); 
};

const handleCombatStateChange = (updatedCombatants, logs, changeset) => {
    setknowledge(prevKnowledge => {
        const newKnowledge = JSON.parse(JSON.stringify(prevKnowledge));
        
        updatedCombatants.forEach(updatedChar => {
            const charIndex = newKnowledge.characters.findIndex(c => c.id === updatedChar.id);
            if (charIndex !== -1) {
                newKnowledge.characters[charIndex] = updatedChar;
            }
        });
        
        // <<< THAY ĐỔI CỐT LÕI NẰM Ở ĐÂY >>>
        // Nhận trạng thái hồi chiêu từ CombatLoop và cập nhật vào state chính
        if (changeset && changeset.sharedCooldowns) {
            newKnowledge.sharedCooldowns = changeset.sharedCooldowns;
        }
        
        return newKnowledge;
    });

    if (logs && Array.isArray(logs) && logs.length > 0 && logs.every(log => log && log.actor)) {
        setCombatLog(prevLog => [...prevLog, ...logs]);
    }
};

const handleActionRequest = async (turnTaker, isFirstTurn = false, options = {}, combatLoopInstance) => {
    if (!turnTaker.isPlayer || options.isControlled) {
        setIsProcessingAction(true);
    } else if (!options.isContinuation) {
        setIsProcessingAction(false);
    }
 
    // 1. TRƯỜNG HỢP: BỊ KHỐNG CHẾ (Choáng/Ngủ...)
    if (options.isControlled) {
        const controllingStatus = (turnTaker.combatStatuses || []).find(s => {
             const sDef = STATUS_LIBRARY[s.status_id] || s;
             return (sDef.special_flags && sDef.special_flags.includes("SKIP_TURN")) || (s.stat_modifications && s.stat_modifications.some(mod => mod.stat_name === "ACTION_DISABLED"));
        });
        const statusName = controllingStatus?.status_name || "bị khống chế";
        
        // Không cần AI tường thuật nữa, ghi thẳng vào log lịch sử
        setStoryHistory(prev => [...prev, { 
            id: crypto.randomUUID(), 
            type: 'system', 
            content: `**[Chiến đấu]** ${turnTaker.Name} không thể hành động do [${statusName}]!` 
        }]);
 
        await combatLoopInstance.processEndOfTurnEffects(turnTaker.id);
        await combatLoopInstance.nextTurn();
        return;
    }
 
    // 2. TRƯỜNG HỢP: NGƯỜI CHƠI RA CHIÊU
    if (turnTaker.isPlayer) {
        if (options.skillToUse) {
            const { skillToUse, target } = options;
            
            // Bỏ qua gọi AI kể chuyện. Thực thi combat ngay lập tức!
            setStoryHistory(prev => [...prev, { 
                id: crypto.randomUUID(), 
                type: 'user_choice', 
                content: `Sử dụng [${skillToUse.Name}] lên ${target ? target.Name : 'bản thân'}.` 
            }]);

            await combatLoopInstance.handleAction(skillToUse, target ? target.id : null);
            return;
        }
        
        setCombatUIState({ view: 'main', items: [] });
        setChoices(options.availableActions || combatLoopInstance.getAvailableActions(turnTaker));
        return; 
    }
 
    // 3. TRƯỜNG HỢP: LƯỢT CỦA AI (Đồng hành hoặc Kẻ địch)
    let allUsableActionNames = ["Đánh Thường"];
    let promptForAITurn = '';
    
    // Lấy danh sách kỹ năng chưa bị cooldown
    const isSilenced = (turnTaker.combatStatuses || []).some(s => (STATUS_LIBRARY[s.status_id] || s).special_flags?.includes("CANNOT_USE_ACTIVE_SKILLS"));
    if (!isSilenced) {
        const skillPool = turnTaker.isCompanion ? Object.values(turnTaker.equippedSkills || {}).filter(Boolean) : (turnTaker.skills || []);
        const usableSkills = skillPool.filter(skill => skill.skillType === 'combat' && (skill.currentCooldown || 0) === 0).map(skill => skill.Name);
        allUsableActionNames.push(...usableSkills);
    }
 
    // Lập prompt siêu ngắn gọn ép AI trả về thẻ lệnh nhanh nhất
    promptForAITurn = `
        VAI TRÒ: Ngươi là Engine điều khiển NPC chiến đấu.
        LƯỢT HIỆN TẠI: ${turnTaker.Name} (Vai trò: ${turnTaker.Role || 'Không rõ'}, HP: ${turnTaker.hp}/${turnTaker.maxhp})
        MỤC TIÊU PHÙ HỢP CÓ THỂ CHỌN: ${combatLoopInstance.allCombatants.filter(c => c.hp > 0 && c.id !== turnTaker.id).map(c => c.Name).join(', ')}
        KỸ NĂNG ĐANG SẴN SÀNG: [${allUsableActionNames.join(', ')}]
        
        MỆNH LỆNH TỐI CAO: Dựa vào logic, hãy chọn 1 Kỹ năng và 1 Mục tiêu. 
        CHỈ TRẢ VỀ ĐÚNG 1 DÒNG DUY NHẤT LÀ THẺ LỆNH NÀY: [USE_SKILL: Skill="Tên Kỹ Năng", Target="Tên Mục Tiêu"]. 
        TUYỆT ĐỐI KHÔNG VIẾT VĂN BẢN TƯỜNG THUẬT HAY BẤT CỨ TỪ NGỮ NÀO KHÁC.
    `;
    
    // Gọi API. Quá trình này giờ sẽ cực nhanh (1-2 giây) vì output rất ngắn.
    const result = await callGeminiAPI(promptForAITurn, false, { isAITurn: true }, undefined);
 
    if (result && result.updates && result.updates.combatAction) {
        const { combatAction } = result.updates;
        const skillToUse = findSkillFromActionText(combatAction.Skill, turnTaker, combatLoopInstance.allCombatants);
        const target = findTargetFromActionText(combatAction.Target, combatLoopInstance.allCombatants, turnTaker);
 
        if (skillToUse) {
            await combatLoopInstance.handleAction(skillToUse, target ? target.id : null);
        } else {
            await combatLoopInstance.nextTurn();
        }
    } else {
        await combatLoopInstance.nextTurn();
    }
};


const formatPartyInfo = (party, isWinner) => {
    if (!party || party.length === 0) return "Không có.";
    
    return party.map(p => {
        let name = p.Name || "Không rõ tên";
        if (p.isPlayer) {
            name += " (đây là nhân vật chính)";
        }
        
        const role = p.Role || "Chưa rõ vai trò";
        // THAY ĐỔI CỐT LÕI NẰM Ở ĐÂY
        // Tự động xác định trạng thái dựa trên HP thay vì dựa vào thuộc tính 'combatStatus'
        const status = p.hp <= 0 ? 'Vô hiệu' : 'Còn khả năng chiến đấu';
        
        const personality = p.Personality ? `Tính cách: ${p.Personality}` : "";
        const description = p.description? `Mô tả: ${p.description.substring(0, 150)}...` : "";
        
        const details = [personality, description].filter(Boolean).join('. ');

        // Chuỗi trả về đã được cập nhật với trạng thái mới
        return `- ${name} (Vai trò: ${role}, Trạng thái: ${status}). ${details}`;
    }).join('\n    ');
};


const startCombat = async (playerParty_Objects, enemiesToFight_Objects, combatType = 'Lethal') => {
   if (!enemiesToFight_Objects || enemiesToFight_Objects.length === 0 || !playerParty_Objects || playerParty_Objects.length === 0) {
       console.error("Lỗi startCombat: Mảng nhân vật tham chiến rỗng hoặc không hợp lệ.");
       setModalMessage({ show: true, title: "Lỗi Hệ Thống", content: "Không thể bắt đầu trận đấu do thiếu thông tin nhân vật.", type: 'error' });
       return;
   }
   
   setIsLoading(true);
   setIsProcessingAction(true); 
   const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";
   
   // --- BƯỚC 1: LỌC TEMPLATE QUÁI VẬT (ĐỒNG BỘ NGOẠI HÌNH) ---
   // Gom nhóm các kẻ địch giống nhau (Cùng tên) để chỉ fetch API 1 lần
   const uniqueEnemyTemplates =[];
   const enemyMap = new Map();

   enemiesToFight_Objects.forEach(enemy => {
       if (!enemyMap.has(enemy.Name)) {
           enemyMap.set(enemy.Name, { ...enemy });
           uniqueEnemyTemplates.push(enemyMap.get(enemy.Name));
       }
   });

   try {
        // Xử lý song song việc chuẩn bị Kỹ năng & Ảnh cho các Template
        setModalMessage({ show: true, title: "Chuẩn Bị Giao Tranh (1/2)", content: `Đấng đang phác họa hình hài và kỹ năng cho các thực thể...`, type: "info" });
        
        const allTemplatesToProcess = [...playerParty_Objects, ...uniqueEnemyTemplates];
        
        for (let i = 0; i < allTemplatesToProcess.length; i++) {
            let char = allTemplatesToProcess[i];
            
            // 1.1 TẠO KỸ NĂNG (Chỉ dành cho NPC/Quái chưa có kỹ năng)
            if (!char.isPlayer && !char.isCompanion && (!char.skills || char.skills.length === 0)) {
                const determinedRarity = getFinalRarityByLevel(char.level);
                try {
                    const skillIdea = await generateNpcSkillIdea(char, determinedRarity, effectiveApiKey);
                    if (skillIdea) {
                        const preliminaryDetails = { skillType: 'combat', skillCategory: 'basic' };
                        const detailedSkillIdea = { ...skillIdea, ...preliminaryDetails, rarity: determinedRarity };
                        const fullSkill = await fetchSkillDetailsFromAI(detailedSkillIdea, gameSettings, effectiveApiKey);
                        if (fullSkill) char.skills = [fullSkill];
                    }
                } catch (skillErr) {
                    console.warn(`Bỏ qua tạo kỹ năng cho ${char.Name} do lỗi:`, skillErr);
                }
            }

            // 1.2 TẠO ẢNH SPRITE
            if (!char.images) char.images = { base: null, idle: null, attack_normal: null, skills: {} };

            const combatSkills = (char.isPlayer || char.isCompanion) 
                ? Object.values(char.equippedSkills || {}).filter(s => s && s.skillType === 'combat')
                : (char.skills ||[]).filter(s => s && s.skillType === 'combat');

            let needToGenerateSomething = false;
            if (!char.images.base || !char.images.idle || !char.images.attack_normal) needToGenerateSomething = true;
            for (const skill of combatSkills) {
                if (!char.images.skills[skill.id]) needToGenerateSomething = true;
            }

            if (needToGenerateSomething) {
                try {
                    let baseImgUrl = char.images.base;
                    let baseMass = char.metadata?.normalizedBaseMass || null;

                    if (!baseImgUrl) {
                        const role = char.Role ? `Role/Profession: ${char.Role}. ` : "";
                        const desc = char.Appearance || char.description || "";
                        const baseCombatPrompt = `A single full body sprite for a 2D turn-based RPG game. Theme: ${gameSettings.theme}. ${role}Appearance: ${desc.substring(0, 250)}. CRITICAL INSTRUCTION: EXACTLY FACING RIGHT (Profile/Side view). Pose: Default combat stance appropriate for its species. STRICTLY RESPECT THE DESCRIBED FORM (If it is an animal, monster, or creature like a wolf or octopus, DO NOT make it humanoid/bipedal). EXTREMELY IMPORTANT: PURE SOLID #FFFFFF WHITE BACKGROUND ONLY. DO NOT USE BLACK OR DARK BACKGROUNDS. CLEAR DAYLIGHT LIGHTING. NO SCENERY. THICK BLACK OUTLINE. 2D flat art style. NO 3D.`;
                        
                        const rawImageBase64 = await generateSingleImage(baseCombatPrompt, effectiveApiKey);
                        const processedBase = await processSprite(rawImageBase64, null);
                        baseImgUrl = processedBase.url;
                        baseMass = processedBase.normalizedMass;
                        char.images.base = baseImgUrl;
                        if (!char.metadata) char.metadata = {};
                        char.metadata.normalizedBaseMass = baseMass;
                        char.metadata.visualCenterY = processedBase.visualCenterY;

                        if (char.isPlayer || char.isCompanion) {
                            await storeAvatarInIndexedDB(char.id, baseImgUrl);
                            char.avatarStoredLocally = true;
                        }
                        
                        if (!char.avatarBase64 && !char.avatarUrl) {
                            char.avatarBase64 = baseImgUrl; 
                        }
                    }

                    const charDesc = `${char.Role || ''} ${char.Appearance || ''} ${char.description || ''}`.toLowerCase();
                    const isRanged = charDesc.match(/cung|nỏ|súng|pháp sư|phù thủy|ám khí|tiêu|ranged|bow|gun|magic|spell/);
                    const atkPoseType = isRanged ? "DYNAMIC: Aiming and shooting a ranged attack or casting a spell" : "DYNAMIC: Swinging weapon forward for a melee strike";

                    if (!char.images.idle) char.images.idle = await generateSpecificPose("Resting/breathing combat pose", baseImgUrl, baseMass, effectiveApiKey) || baseImgUrl;
                    if (!char.images.attack_normal) char.images.attack_normal = await generateSpecificPose(atkPoseType, baseImgUrl, baseMass, effectiveApiKey) || baseImgUrl;

                    for (const skill of combatSkills) {
                        if (!char.images.skills[skill.id]) {
                            const skillPrompt = `Action pose: Performing a move related to "${skill.Name || targetSkill.Name}". Base concept: ${(skill.description || targetSkill.description) || 'Physical attack'}. CRITICAL INSTRUCTION: The character's body MUST remain EXACTLY the same size, scale, and proportions as the reference image. EXTREMELY IMPORTANT: PURE SOLID #FFFFFF WHITE BACKGROUND ONLY. DO NOT USE BLACK OR DARK BACKGROUNDS. CLEAR DAYLIGHT LIGHTING. NO SCENERY. NO SHADOWS ON THE GROUND. ABSOLUTELY NO VISUAL EFFECTS (VFX). DO NOT draw magic, fire, glowing auras, energy, or impact flashes. ONLY draw the pure physical character model (and their held weapons) in a dynamic physical stance.`;
                            char.images.skills[skill.id] = await generateSpecificPose(skillPrompt, baseImgUrl, baseMass, effectiveApiKey, true) || char.images.attack_normal || baseImgUrl;
                        }
                    }

                } catch (imgError) {
                    console.warn(`[CẢNH BÁO] Không thể vẽ ảnh cho NPC "${char.Name}". Dùng avatar mặc định. Lỗi:`, imgError.message);
                    char.avatarError = true;
                }
            }
        }

        // 1.3 NHÂN BẢN DỮ LIỆU TỪ TEMPLATE CHO TẤT CẢ QUÁI VẬT
        const enemiesWithSkills = enemiesToFight_Objects.map(enemy => {
            const template = enemyMap.get(enemy.Name);
            return {
                ...enemy,
                // Deep clone skills để hồi chiêu độc lập
                skills: template.skills ? JSON.parse(JSON.stringify(template.skills)) :[],
                // Shallow clone images để dùng chung RAM
                images: template.images,
                metadata: template.metadata,
                avatarError: template.avatarError
            };
        });

        // Cập nhật Knowledge
        setknowledge(prevKnowledge => {
            const newKnowledge = JSON.parse(JSON.stringify(prevKnowledge));
            enemiesWithSkills.forEach(updatedEnemy => {
                const index = newKnowledge.characters.findIndex(c => c.id === updatedEnemy.id);
                if (index > -1) {
                    newKnowledge.characters[index].skills = updatedEnemy.skills;
                    newKnowledge.characters[index].images = updatedEnemy.images; 
                }
            });
            playerParty_Objects.forEach(playerChar => {
                const index = newKnowledge.characters.findIndex(c => c.id === playerChar.id);
                if (index > -1) {
                    newKnowledge.characters[index].avatarStoredLocally = playerChar.avatarStoredLocally;
                    if (playerChar.avatarBase64) {
                        newKnowledge.characters[index].avatarBase64 = playerChar.avatarBase64;
                    }
                }
            });
            return newKnowledge;
        });

        // --- BƯỚC 2: TÀNG THƯ ĐỊA ĐIỂM (CACHE ẢNH NỀN) VÀ INTRO ---
        setModalMessage({ show: true, title: "Chuẩn Bị Giao Tranh (2/2)", content: "Đấng đang phác họa chiến trường...", type: "info" });
        let battleIntroText = "Trận chiến bắt đầu!";
        let finalBgUrl = null;
        
        try {
            const playerLoc = knowledge.locations.find(l => l.id === playerParty_Objects[0]?.current_location_id);
            const locName = playerLoc ? playerLoc.Name : "Khu vực hoang vắng";
            const locDesc = playerLoc ? playerLoc.description : "";
            
            // Kiểm tra cache ảnh nền
            if (playerLoc && playerLoc.arenaBackgroundUrl) {
                console.log("Đã tìm thấy ảnh nền Arena trong Cache, tải ngay lập tức!");
                finalBgUrl = playerLoc.arenaBackgroundUrl;
            }
            
            // Xây dựng prompt để lấy Intro Text (và Bg Prompt nếu cần vẽ nền)
            const introPrompt = `
                A combat is starting in the game.
                Location Name: ${locName}. Location Details: ${locDesc}. Weather: ${knowledge.weather}. Theme: ${gameSettings.theme}.
                Player side: ${playerParty_Objects.map(p=>p.Name).join(', ')}.
                Enemy side: ${enemiesWithSkills.map(e=>e.Name).join(', ')}.
                
                Return a JSON object EXACTLY like this:
                {
                   "narrative": "Viết đoạn văn tiếng Việt mô tả khoảnh khắc chạm trán giữa hai bên tại địa điểm này.",
                   "bgPrompt": ${finalBgUrl ? '""' : '"Detailed description of a 2D fighting game stage based on the location. CRITICAL INSTRUCTION: The bottom 40% to 50% of the image MUST be a solid, flat, walkable ground floor texture. The top 50% to 60% MUST be the background sky and scenery. Perfect horizontal horizon line. MUST specify \'2D flat hand-drawn style, game asset\'. DO NOT include text, borders, vignette, or characters."'}
                }
            `;
            const schema = { type: "OBJECT", properties: { narrative: { type: "STRING" }, bgPrompt: { type: "STRING" } }, required:["narrative", "bgPrompt"] };
            const payload = { contents:[{ role: "user", parts:[{ text: introPrompt }] }], generationConfig: { response_mime_type: "application/json", response_schema: schema } };
            const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;
            
            const jsonText = await fetchWithRetries(apiUrl, payload);
            const parsedIntro = JSON.parse(jsonText);
            battleIntroText = parsedIntro.narrative;
            
            // Nếu chưa có cache, gọi Imagen để vẽ nền
            if (!finalBgUrl && parsedIntro.bgPrompt) {
                finalBgUrl = await generateCombatEnvironment(parsedIntro.bgPrompt, effectiveApiKey);
                
                // Lưu ảnh vào Tàng Thư (Cache)
                if (finalBgUrl && playerLoc) {
                    setknowledge(prev => {
                        const newK = JSON.parse(JSON.stringify(prev));
                        const locIdx = newK.locations.findIndex(l => l.id === playerLoc.id);
                        if (locIdx > -1) {
                            newK.locations[locIdx].arenaBackgroundUrl = finalBgUrl;
                        }
                        return newK;
                    });
                }
            }
            
            setCombatEnvironmentImage(finalBgUrl);
            
        } catch (err) {
            console.warn("Lỗi tạo intro/nền, dùng mặc định:", err);
            setCombatEnvironmentImage(null);
        }

        // --- BƯỚC 3: MỞ MÀN ---
        const refreshedPlayerParty = playerParty_Objects.map(p => calculateFinalStats(p));
        const refreshedEnemies = enemiesWithSkills.map(e => calculateFinalStats(e));

        setModalMessage({ show: false, title: "", content: "", type: "info" });
        setIsLoading(false);
        setIsProcessingAction(false);
        
        setCombatInitializationData({
            playerParty: refreshedPlayerParty,
            enemies: refreshedEnemies,
            combatType: combatType
        });

        setGameMode('COMBAT');
        setChoices([]);
        
        setCombatLog([{
            id: crypto.randomUUID(),
            round: 0,
            actor: "Hệ thống",
            skill: "",
            target: "",
            message: battleIntroText
        }]);

   } catch (error) {
       console.error("Lỗi nghiêm trọng trong quá trình chuẩn bị combat:", error);
       setModalMessage({ show: true, title: "Lỗi Hệ Thống", content: `Quá trình chuẩn bị gián đoạn: ${error.message}`, type: "error" });
       setIsLoading(false);
       setIsProcessingAction(false);
       return;
   }   
};


const calculateTotalAP = (level) => {
    if (level <= 1) return 5;
    const apFromLevels = (level - 1) * 5;
    const breakthroughs = Math.floor((level - 1) / 10);
    const apFromBreakthroughs = breakthroughs * 10;
    return 5 + apFromLevels + apFromBreakthroughs;
};
const calculateBonusAp = (difficulty, turnCount, monthCount) => {
    let apFromTurns = 0;
    let apFromMonths = 0;
    const MAX_BONUS_AP = 200;

    if (difficulty === 'Thường' || difficulty === 'Dễ') {
        apFromTurns = Math.floor(turnCount / 30) * 2;
        apFromMonths = Math.floor(monthCount / 2) * 3;
    } else if (difficulty === 'Khó' || difficulty === 'Ác Mộng') {
        apFromTurns = Math.floor(turnCount / 30) * 3;
        apFromMonths = Math.floor(monthCount / 2) * 4;
    }
    
    const totalBonus = apFromTurns + apFromMonths;
    
    return Math.min(totalBonus, MAX_BONUS_AP);
};


const applyNpcDesign = (currentKnowledge, npcId, npcDesign) => {
    let newKnowledge = JSON.parse(JSON.stringify(currentKnowledge));
    const npcIndex = newKnowledge.characters.findIndex(c => c.id === npcId);

    if (npcIndex > -1) {
        let npc = newKnowledge.characters[npcIndex];
        
        // 1. Phân phối điểm AP vào chỉ số GỐC
        // KHÔNG tính lại baseStats từ level nữa.
        // Thay vào đó, ta sẽ cộng dồn vào baseStats hiện có của NPC.
        if (npcDesign.apDistribution) {
            const apAllotment = parseStatsBonus(npcDesign.apDistribution);
            for (const stat in apAllotment) {
                const points = apAllotment[stat];
                // Cộng trực tiếp vào chỉ số gốc (base)
                if (stat === 'hp') npc.baseHp += points * 20; // Ví dụ: 1 điểm AP = 20 HP
                else if (stat === 'atk') npc.baseAtk += points * 1;
                else if (stat === 'def') npc.baseDef += points * 1;
                else if (stat === 'spd') npc.baseSpd += points * 1;
            }
        }
        
        // 2. Thêm kỹ năng
        if (npcDesign.skills && Array.isArray(npcDesign.skills)) {
            // Đảm bảo mỗi kỹ năng có một ID duy nhất và hồi chiêu ban đầu là 0
            npc.skills = npcDesign.skills.map(skill => ({
                id: crypto.randomUUID(),
                ...skill,
                currentCooldown: 0,
            }));
        }

        // 3. TÍNH TOÁN LẠI CHỈ SỐ CUỐI CÙNG
        // Sau khi đã có base stats và skills mới, gọi hàm calculateFinalStats
        // để cập nhật lại hp, maxhp, atk... cuối cùng của NPC.
        newKnowledge.characters[npcIndex] = calculateFinalStats(npc);
    }

    return newKnowledge;
};


const applyCombatResults = (currentKnowledge, combatResults) => {
    // Luôn làm việc trên một bản sao sâu
    let newKnowledge = JSON.parse(JSON.stringify(currentKnowledge));

    // "Giải nén" đối tượng combatResults để lấy ra kết quả và ID người tấn công
    const { results, casterId } = combatResults;
    if (!results || !casterId) {
        console.error("Lỗi áp dụng kết quả combat: Dữ liệu không hợp lệ.");
        return newKnowledge; // Trả về state không đổi nếu có lỗi
    }

    // --- BƯỚC 1: ÁP DỤNG HIỆU ỨNG LÊN CÁC MỤC TIÊU ---
    results.effectsOnTargets.forEach(resultOnTarget => {
        const targetIndex = newKnowledge.characters.findIndex(c => c.id === resultOnTarget.targetId);
        if (targetIndex > -1) {
            let target = newKnowledge.characters[targetIndex];

            // Trừ HP do sát thương chính
            target.hp -= resultOnTarget.damageDealt || 0;

            // Cộng HP do hồi máu chính
            target.hp += resultOnTarget.healingDone || 0;

            // Áp dụng trạng thái mới (buff/debuff) từ kỹ năng
            if (resultOnTarget.statusApplied && resultOnTarget.statusApplied.length > 0) {
                if (!target.combatStatuses) target.combatStatuses = [];
                // Chuyển đổi chuỗi thành đối tượng nếu cần
                const statuses = Array.isArray(resultOnTarget.statusApplied) 
                    ? resultOnTarget.statusApplied 
                    : [parseKeyValueString(resultOnTarget.statusApplied)];
                target.combatStatuses.push(...statuses);
            }
        }
    });

    // --- BƯỚC 2: ÁP DỤNG CÁC HIỆU ỨNG PHỤ LÊN NGƯỜI TẤN CÔNG (CASTER) ---
    const casterIndex = newKnowledge.characters.findIndex(c => c.id === casterId);
    if (casterIndex > -1) {
        let caster = newKnowledge.characters[casterIndex];

        // 2a. Áp dụng sát thương Phản đòn lên người tấn công
        const totalThornsDamage = results.effectsOnTargets.reduce((sum, r) => sum + (r.thornsDamage || 0), 0);
        if (totalThornsDamage > 0) {
            caster.hp -= totalThornsDamage;
        }

        // 2b. Áp dụng hồi máu từ Hút máu cho người tấn công
        const totalHealingFromLifesteal = results.casterEffects?.healing || 0;
        if (totalHealingFromLifesteal > 0) {
            caster.hp += totalHealingFromLifesteal;
        }
    }
    
    // --- BƯỚC 3: ĐẢM BẢO TÍNH TOÀN VẸN DỮ LIỆU (HP không âm, không vượt max) ---
    newKnowledge.characters.forEach(char => {
        if (char.hp < 0) {
            char.hp = 0;
        }
        if (char.hp > char.maxhp) {
            char.hp = char.maxhp;
        }
    });

    return newKnowledge;
};


const processNextTurn = (turnIndex, turnOrder, combatants, round) => {
    
    // ===================================================================
    // A. XỬ LÝ KHI MỘT VÒNG ĐẤU KẾT THÚC
    // ===================================================================
    if (turnIndex >= turnOrder.length) {
        const nextRound = round + 1;
        setCombatRound(nextRound); // Cập nhật state cho UI hiển thị
        console.log(`--- KẾT THÚC VÒNG ${round}, BẮT ĐẦU VÒNG ${nextRound} ---`);

        // A.1. XỬ LÝ HIỆU ỨNG CUỐI VÒNG & GIẢM HỒI CHIÊU
        // Áp dụng cho TẤT CẢ các nhân vật còn sống.
        const combatantsAfterRoundEnd = combatants.map(char => {
            if (char.hp <= 0) return char; // Bỏ qua nhân vật đã chết

            // Giảm thời gian hiệu lực của trạng thái
            const updatedStatuses = (char.combatStatuses || [])
                .map(status => ({ ...status, duration: (status.duration || 1) - 1 }))
                .filter(status => status.duration > 0);
            
            // Giảm hồi chiêu kỹ năng
            const updatedSkills = (char.skills || []).map(skill => ({
                ...skill,
                currentCooldown: Math.max(0, (skill.currentCooldown || 0) - 1)
            }));
            
            return { ...char, combatStatuses: updatedStatuses, skills: updatedSkills };
        });

        // A.2. TÍNH TOÁN LẠI THỨ TỰ LƯỢT ĐI CHO VÒNG MỚI (BAO GỒM LƯỢT THÊM)
        const aliveCombatants = combatantsAfterRoundEnd.filter(c => c.hp > 0);
        
        // Sắp xếp lại thứ tự cơ bản dựa trên SPD
        let newTurnOrder = aliveCombatants
            .sort((a, b) => b.spd - a.spd)
            .map(c => c.id);

        // Tính toán lượt đi thêm (Extra Turn)
        const spdArray = aliveCombatants.map(c => c.spd);
        if (spdArray.length > 1) {
            const maxSpd = Math.max(...spdArray);
            const minSpd = Math.max(1, Math.min(...spdArray));
            const spdRatio = maxSpd / minSpd;
            
            let extraTurns = 0;
            if (spdRatio >= 4) extraTurns = 2;
            else if (spdRatio >= 2) extraTurns = 1;

            if (extraTurns > 0) {
                const fastestCharId = aliveCombatants.find(c => c.spd === maxSpd)?.id;
                if (fastestCharId) {
                    for (let i = 0; i < extraTurns; i++) {
                        newTurnOrder.push(fastestCharId);
                    }
                    console.log(`Nhân vật ${fastestCharId} nhận được ${extraTurns} lượt đi thêm!`);
                }
            }
        }
        
        setCombatTurnOrder(newTurnOrder); // Cập nhật state thứ tự lượt đi cho UI (nếu cần)

        // A.3. GỌI ĐỆ QUY CHO VÒNG MỚI
        // Truyền trực tiếp các giá trị vừa tính toán xong, không đọc từ state
        processNextTurn(0, newTurnOrder, combatantsAfterRoundEnd, nextRound);
        return; // Dừng hàm hiện tại
    }

    // ===================================================================
    // B. XÁC ĐỊNH NGƯỜI HÀNH ĐỘNG VÀ XỬ LÝ HIỆU ỨNG ĐẦU LƯỢT
    // ===================================================================
    let currentCombatants = [...combatants]; // Tạo bản sao để có thể thay đổi trong hàm
    const turnTakerId = turnOrder[turnIndex];
    let turnTaker = currentCombatants.find(c => c.id === turnTakerId);

    // B.1. Bỏ qua nếu nhân vật không tồn tại hoặc đã bị hạ gục từ trước
    if (!turnTaker || turnTaker.hp <= 0) {
        processNextTurn(turnIndex + 1, turnOrder, currentCombatants, round);
        return;
    }

    // B.2. XỬ LÝ HIỆU ỨNG GÂY SÁT THƯƠNG/HỒI MÁU ĐẦU LƯỢT (DoT/HoT)
    let hpChangeFromStatus = 0;
    (turnTaker.combatStatuses || []).forEach(status => {
        // Ví dụ: Độc, Thiêu đốt, Hồi máu...
        if (status.effectType === 'DOT') hpChangeFromStatus -= status.value || 0;
        if (status.effectType === 'HOT') hpChangeFromStatus += status.value || 0;
    });

    if (hpChangeFromStatus !== 0) {
        turnTaker.hp += hpChangeFromStatus;
        // Cập nhật lại đối tượng nhân vật trong mảng combatants
        currentCombatants = currentCombatants.map(c => c.id === turnTakerId ? turnTaker : c);
        
        const statusEffectMessage = hpChangeFromStatus < 0 
            ? `${turnTaker.Name} mất ${-hpChangeFromStatus} HP vì hiệu ứng trạng thái!` 
            : `${turnTaker.Name} hồi ${hpChangeFromStatus} HP!`;
        setStoryHistory(prev => [...prev, { id: crypto.randomUUID(), type: 'system', content: statusEffectMessage }]);
    }
    
    // B.3. KIỂM TRA LẠI SAU KHI DÍNH HIỆU ỨNG
    if (turnTaker.hp <= 0) {
        turnTaker.hp = 0;
        setStoryHistory(prev => [...prev, { id: crypto.randomUUID(), type: 'system', content: `${turnTaker.Name} đã gục ngã vì hiệu ứng trạng thái!` }]);
        // Cập nhật state combatants lần cuối trước khi chuyển lượt
        setCombatants(currentCombatants); 
        processNextTurn(turnIndex + 1, turnOrder, currentCombatants, round);
        return;
    }

    // Cập nhật state combatants sau khi xử lý hiệu ứng đầu lượt
    setCombatants(currentCombatants);
    
    // ===================================================================
    // C. PHÂN LOẠI LƯỢT ĐI VÀ GỌI AI
    // ===================================================================
    console.log(`Vòng ${round}, Lượt của: ${turnTaker.Name} (HP: ${turnTaker.hp}/${turnTaker.maxhp})`);
    setCurrentCombatantIndex(turnIndex); // Cập nhật state cho UI

    const isPlayerControlled = turnTaker.isPlayer; // Giả sử chỉ player mới do người chơi điều khiển
    const battlefieldStatus = currentCombatants.map(c => `- ${c.Name} (HP: ${c.hp}/${c.maxhp})`).join('\n');

    if (isPlayerControlled) {
        const playerSkills = (turnTaker.skills || [])
            .map(s => `${s.Name} (Hồi: ${s.currentCooldown || 0}/${s.cooldown || 0})`)
            .join('; ') || "Không có.";

        const promptForPlayerTurn = `
            --- BỐI CẢNH CHIẾN ĐẤU {Vòng ${round}, Lượt của ${turnTaker.Name}} ---
            **CHẾ ĐỘ HIỆN TẠI: GIAO ĐẤU**
            
            **Tình hình chiến trường:**
            ${battlefieldStatus}
            
            --- YÊU CẦU ---
            Đã đến lượt của ${turnTaker.Name}.
            Hãy tạo ra danh sách 6 lựa chọn chiến đấu cho họ theo đúng định dạng trong BỘ LUẬT.
            Các kỹ năng của họ là: ${playerSkills}.
        `;
        callGeminiAPI(promptForPlayerTurn);

    } else { // Lượt của AI
        console.log(`AI đang điều khiển ${turnTaker.Name}...`);
        
        const npcSkills = (turnTaker.skills || []).map(s => s.Name).join(', ') || "Không có.";
        const npcStatuses = (turnTaker.combatStatuses || []).map(s => s.name).join(', ') || "Bình thường.";

        const promptForAITurn = `
            --- BỐI CẢNH CHIẾN ĐẤU {Vòng ${round}, Lượt của ${turnTaker.Name}} ---
            **CHẾ ĐỘ HIỆN TẠI: GIAO ĐẤU**
            
            **Thông tin người hành động (${turnTaker.Name}):**
            - Vai trò/Tính cách: "${turnTaker.Role || turnTaker.description|| 'Không rõ'}"
            - Chỉ số: HP ${turnTaker.hp}/${turnTaker.maxhp}, ATK ${turnTaker.atk}, DEF ${turnTaker.def}, SPD ${turnTaker.spd}
            - Kỹ năng: ${npcSkills}
            - Trạng thái hiện tại: ${npcStatuses}

            **Tình hình chiến trường:**
            ${battlefieldStatus}

            --- YÊU CẦU ---
            Đã đến lượt của ${turnTaker.Name}.
            Với vai trò là một AI chiến thuật, hãy phân tích tình hình và chọn hành động tối ưu nhất cho ${turnTaker.Name}.
            Mô tả hành động đó và xuất ra thẻ lệnh [USE_SKILL] tương ứng.
        `;
        callGeminiAPI(promptForAITurn, false, { inCombat: true, isAITurn: true });
    }
};
    const handleSaveSetup = () => {
    // Chỉ lưu gameSettings
    const setupToSave = {
        setupVersion: "1.0", // Để nhận biết và tương thích sau này
        settings: gameSettings,
    };

    const jsonString = JSON.stringify(setupToSave, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    a.href = url;
    // Đặt tên tệp rõ ràng
    a.download = `AI_ThietLap_${gameSettings.theme || 'Untitled'}_${timestamp}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    setModalMessage({ show: true, title: 'Thành Công', content: 'Đã lưu thiết lập khởi đầu vào tệp!', type: 'success' });
};
    // Hàm hỗ trợ: Phân tích chuỗi StatsBonus thành đối tượng
    // Ví dụ: "atk:5,hp:20" -> { atk: 5, hp: 20 }
    const parseStatsBonus = (statsBonusString) => {
        const bonuses = {};
        if (statsBonusString && typeof statsBonusString === 'string' && statsBonusString.trim() !== '[Không có]') {
            statsBonusString.split(',').forEach(part => {
                const [key, value] = part.split(':').map(s => s.trim());
                if (key && !isNaN(parseFloat(value))) {
                    bonuses[key.toLowerCase()] = parseFloat(value);
                }
            });
        }
        return bonuses;
    };

    // Hàm hỗ trợ: Áp dụng bonus vào chỉ số
    // baseStats là chỉ số hiện tại, bonuses là đối tượng từ parseStatsBonus
const applyStatsBonus = (baseStats, bonuses) => {
    const newStats = { ...baseStats };
    for (const key in bonuses) {
        if (newStats.hasOwnProperty(key) && typeof newStats[key] === 'number') {
            // Áp dụng cho các chỉ số như atk, def, spd, maxhp...
            newStats[key] += bonuses[key];
        } else if (key === 'hp' && typeof newStats.maxhp === 'number') { 
            // Trường hợp đặc biệt: cộng vào máu hiện tại nhưng không vượt quá máu tối đa
            // Lưu ý: maxhp đã được cộng ở điều kiện trên
            newStats.hp = Math.min(newStats.maxhp, newStats.hp + bonuses[key]);
        }    }
    return newStats;
};

    // Hàm hỗ trợ: Gỡ bỏ bonus khỏi chỉ số
const removeStatsBonus = (baseStats, bonuses) => {
    // Luôn làm việc trên một bản sao
    const newStats = { ...baseStats };

    for (const key in bonuses) {
        if (newStats.hasOwnProperty(key) && typeof newStats[key] === 'number') {
            // Gỡ bỏ bonus cho các chỉ số như atk, def, spd, maxhp...
            newStats[key] -= bonuses[key];
        } else if (key === 'hp' && typeof newStats.maxhp === 'number') {
            // Trường hợp đặc biệt: trừ máu hiện tại
            // Đảm bảo máu hiện tại không vượt quá máu tối đa mới (sau khi đã trừ bonus từ maxhp)
            newStats.hp = Math.min(newStats.maxhp, newStats.hp - bonuses[key]);
        }
    }

    // Lớp bảo vệ cuối cùng: Đảm bảo các chỉ số không bị âm hoặc dưới mức tối thiểu.
    // Điều này ngăn chặn các lỗi tính toán và giữ cho trạng thái game luôn hợp lệ.
    
    newStats.hp = Math.max(0, newStats.hp);        // HP không thể âm
    newStats.atk = Math.max(0, newStats.atk);      // Tấn công không thể âm
    newStats.def = Math.max(0, newStats.def);      // Phòng thủ không thể âm
    newStats.spd = Math.max(0, newStats.spd);      // Tốc độ không thể âm
    
    // Tỷ lệ chí mạng không thể âm. 
    // Giới hạn tối đa là 100% nếu bạn muốn, nhưng tối thiểu là 0 là đủ.
    newStats.cr = Math.max(0, newStats.cr);
    
    // Sát thương chí mạng có thể có một mức tối thiểu, ví dụ 100% hoặc 0.
    // Ở đây, chúng ta đặt tối thiểu là 0.
    newStats.cdmg = Math.max(0, newStats.cdmg);
    
    return newStats;
};

        
