const generateCombatEnvironment = async (bgPrompt, effectiveApiKey) => {
    if (!bgPrompt) {
        console.error("LỖI: bgPrompt không được truyền vào!");
        return null;
    }

    console.log("Đang gọi API Imagen 4.0 cho CẢNH NỀN với prompt:", bgPrompt);

    try {
        const imgGenUrl = `https://generativelanguage.googleapis.com/v1beta/models/imagen-4.0-generate-001:predict?key=${effectiveApiKey}`;
        
        // CHÉP CHÍNH XÁC PROMPT TỪ GAME GỐC
        const finalPrompt = `${bgPrompt}. Masterpiece 2D flat game art, side-scrolling RPG arena. Zero perspective depth. CRITICAL: The bottom 40% to 50% of the image MUST be the flat ground floor texture. The top part is the background scenery. Clear horizontal horizon. (NO text, NO words, NO watermarks, NO borders, NO vignette, NO white edges, NO UI, NO characters).`;

        const imgPayload = { 
            instances: [{ prompt: finalPrompt }], 
            parameters: { sampleCount: 1 } 
        };
        
        const stageRes = await fetch(imgGenUrl, { 
            method: 'POST', 
            headers: { 'Content-Type': 'application/json' }, 
            body: JSON.stringify(imgPayload) 
        });

        if (!stageRes.ok) {
            const errText = await stageRes.text();
            console.error("Lỗi API Imagen 4.0 (Cảnh nền):", errText);
            throw new Error("Imagen API lỗi");
        }
        
        const stageData = await stageRes.json();
        if (stageData.predictions?.[0]?.bytesBase64Encoded) {
            console.log("Tạo Ảnh Nền THÀNH CÔNG!");
            return `data:image/jpeg;base64,${stageData.predictions[0].bytesBase64Encoded}`;
        }
        return null;
    } catch (e) {
        console.warn("Lỗi khi vẽ cảnh nền combat, sử dụng cảnh nền CSS mặc định:", e);
        return null; 
    }
};

