const handleDiscardItem = (itemIdToDiscard) => {
    if (!playerCharacter || !playerCharacter.inventory) {
        console.error("Lỗi: handleDiscardItem được gọi khi playerCharacter hoặc inventory không tồn tại.");
        return;
    }

    const item = playerCharacter.inventory.find(i => i.id === itemIdToDiscard);
    if (!item) return;

    const discardLogic = (itemToDiscard, quantity) => {
        setConfirmationModal({
            show: true,
            title: `Xác Nhận Vứt Bỏ`,
            content: `Ngươi có chắc chắn muốn vứt bỏ ${quantity} x "${itemToDiscard.Name}" không? Hành động này không thể hoàn tác.`,
            onConfirm: () => {
                // Dùng hàm helper tập trung để xóa item
                const newKnowledge = updatePlayerInventory(knowledge, itemToDiscard.id, quantity);
                setknowledge(newKnowledge);
                
                setModalMessage({ show: true, title: 'Đã Vứt Bỏ', content: `Đã vứt bỏ ${quantity} x "${itemToDiscard.Name}".`, type: 'success' });
            },
            confirmText: 'Chắc Chắn Vứt',
            cancelText: 'Hủy Bỏ'
        });
    };

    if ((item.quantity || 1) > 1) {
        // Mở QuantitySelector với các hàm xử lý
        setQuantitySelector({
            show: true,
            item: item,
            title: `Chọn số lượng "${item.Name}" để vứt:`,
            onConfirm: (selectedItem, quantity) => {
                discardLogic(selectedItem, quantity);
                setQuantitySelector({ show: false, item: null }); // Đóng lại sau khi xác nhận
            },
            onCancel: () => setQuantitySelector({ show: false, item: null }) // Chỉ cần đóng lại
        });
    } else {
        // Nếu chỉ có 1, hỏi thẳng
        discardLogic(item, 1);
    }
};



    const parseEffectString = (effectString) => {
        // Trả về null nếu chuỗi đầu vào không hợp lệ
        if (!effectString || typeof effectString !== 'string' || effectString.trim() === '') {
            return null;
        }

        const effect = { special_properties: {} }; // Khởi tạo với special_properties để chứa các flag
        const properties = effectString.split(',');
        
        const targetInfo = {};

        properties.forEach(prop => {
            const parts = prop.split(':');
            const key = parts[0]?.trim().toLowerCase(); // Chuẩn hóa key về chữ thường
            // Nối lại các phần còn lại của value trong trường hợp value chứa dấu ':'
            const value = parts.slice(1).join(':')?.trim();

            if (!key || value === undefined) return;

            // Gom các thuộc tính của target vào một object tạm
            if (key === 'target' || key === 'count') {
                targetInfo[key] = key === 'count' ? parseInt(value, 10) : value;
                return;
            }
            
            // Xử lý các key-value đơn giản
            switch (key) {
                case 'effecttype':
                    effect.effectType = value;
                    break;
                case 'formula':
                    effect.formula = value;
                    break;
                // Các thuộc tính của trạng thái được thêm trực tiếp vào effect
                case 'status_id':
                case 'duration':
                case 'status_name':
                case 'status_type':
                case 'stat_changes':
                case 'special_flags':
                    effect[key] = (key === 'duration') ? parseInt(value, 10) : value;
                    break;
                // Các thuộc tính đặc biệt của sát thương
                case 'true_damage':
                    effect.special_properties.true_damage = (value === 'true');
                    break;
                case 'armor_penetration':
                    effect.special_properties.armor_penetration = parseFloat(value) / 100;
                    break;
                case 'can_crit':
                    effect.special_properties.can_crit = (value === 'true');
                    break;
            }
        });

        // Gán đối tượng target hoàn chỉnh
        if (targetInfo.target) {
            effect.target = { type: targetInfo.target, count: targetInfo.count || 0 };
        } else {
             // Nếu không có target rõ ràng, mặc định là single để tránh lỗi
             effect.target = { type: 'single', count: 0 };
        }

        // Trả về effect chỉ khi có effectType
        return effect.effectType ? effect : null;
    };



const handleGenerateImpromptuCharacter = async () => {
    if (!impromptuCharInput.trim()) {
        setModalMessage({ show: true, title: 'Thiếu Thông Tin', content: 'Vui lòng nhập tên nhân vật hoặc mô tả ngắn.', type: 'error' });
        return;
    }

    setIsGeneratingImpromptuChar(true);
    setModalMessage({ show: true, title: 'Đấng đang nặn người', content: 'Đấng đang dựa vào ý tưởng của ngươi để tạo ra một sinh linh mới... Vui lòng đợi trong giây lát.', type: 'info' });

    const effectiveApiKey = apiMode === 'defaultGemini' ? "" : apiKey;
    if (apiMode === 'userKey' && !effectiveApiKey) {
        setModalMessage({ show: true, title: 'Lỗi API Key', content: 'Vui lòng cấu hình API Key.', type: 'error' });
        setIsGeneratingImpromptuChar(false);
        return;
    }

    const prompt = `
        Bạn là một chuyên gia sáng tạo nhân vật. Dựa trên ý tưởng: "${impromptuCharInput}", và bối cảnh game "${gameSettings.theme}", hãy tạo ra MỘT nhân vật hoàn chỉnh.

        CHECKLIST (BẮT BUỘC THỰC HIỆN):
        1.  Tạo "name", "gender", "personality", "role", "appearance", "backstory", "goal".
        2.  Tạo một MẢNG tên là "initialTraits" chứa từ 2 ĐẶC ĐIỂM KHỞI ĐẦU.
        3.  Với MỖI đặc điểm trong mảng đó, PHẢI có 3 thuộc tính:
            *   "category": Quyết định xem nó là "Kỹ năng" hay "Vật phẩm".
            *   "name": Đặt một cái tên hấp dẫn.
            *   "description": Viết một mô tả ngắn gọn, gợi mở.

        DANH SÁCH TÍNH CÁCH CHO PHÉP: ${PLAYER_PERSONALITIES.join(', ')}

        CHỈ trả về một đối tượng JSON duy nhất theo đúng cấu trúc schema.
    `;

    const schema = {
        type: "OBJECT",
        properties: {
            name: { type: "STRING" },
            gender: { type: "STRING", enum: ["Nam", "Nữ", "Khác", "Không xác định"] },
            personality: { type: "STRING", enum: PLAYER_PERSONALITIES },
            role: { type: "STRING" },
            appearance: { type: "STRING" },
            backstory: { type: "STRING" },
            goal: { type: "STRING" },
            initialTraits: {
                type: "ARRAY",
                items: {
                    type: "OBJECT",
                    properties: {
                        category: { type: "STRING", enum: ["Kỹ năng", "Vật phẩm"] },
                        name: { type: "STRING" },
                        description: { type: "STRING" }
                    },
                    required: ["category", "name", "description"]
                }
            }
        },
        required: ["name", "gender", "personality", "role", "appearance", "backstory", "goal", "initialTraits"]
    };

    const payload = {
        contents: [{ role: "user", parts: [{ text: prompt }] }],
        generationConfig: {
            response_mime_type: "application/json",
            response_schema: schema,
        }
    };
    
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

    try {
        const response = await fetch(apiUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        });
        const result = await response.json();

        if (result.candidates && result.candidates[0]?.content?.parts[0]?.text) {
            const jsonText = result.candidates[0].content.parts[0].text;
            const data = JSON.parse(jsonText);

            setGameSettings(prev => ({
                ...prev,
                characterName: data.name,
                characterGender: data.gender,
                characterPersonality: data.personality,
                characterRole: data.role,
                characterAppearance: data.appearance,
                characterBackstory: data.backstory,
                useCharacterGoal: true,
                characterGoal: data.goal,
                initialTraits: (data.initialTraits || []).map(trait => ({
                    ...trait,
                    id: crypto.randomUUID(),
                    description: trait.description || '[Chưa có]',
                })),
                customCharacterPersonality: '',
            }));
            
            setModalMessage({ show: true, title: 'Nhân Vật Hoàn Tất', content: 'Đấng đã tạo xong các thiết lập cơ bản cho nhân vật của ngươi!', type: 'success' });

        } else {
            const errorMsg = result.error?.message || "Không thể lấy dữ liệu từ AI. Phản hồi không hợp lệ.";
            throw new Error(errorMsg);
        }
    } catch (error) {
        console.error("Lỗi khi tạo nhanh nhân vật:", error);
        setModalMessage({ show: true, title: 'Lỗi AI', content: `Không thể tạo nhanh nhân vật: ${error.message}`, type: 'error' });
    } finally {
        setIsGeneratingImpromptuChar(false);
    }
};
    const fetchWorldInfo = async (idea) => {
        const effectiveApiKey = apiMode === 'defaultGemini' ? "" : apiKey;
        const prompt = `
            Bạn là một chuyên gia sáng tạo thế giới. Dựa trên ý tưởng: "${idea}", hãy tạo ra các yếu tố cốt lõi sau:
            
            1. "storyTitle": Tên của thế giới.
            2. "genre": Thể loại chính (VD: Tiên hiệp, Khoa huyễn).
            3. "tags": Một chuỗi 3-5 tag mô tả, cách nhau bởi dấu phẩy.
            4. "setting": Một đoạn mô tả bối cảnh chi tiết (3-5 câu).
            5. "writingStyle": Chọn MỘT phong cách phù hợp nhất từ danh sách: ${WRITING_STYLES.join(', ')}.
            6. "currencyName": Tên một đơn vị tiền tệ phù hợp.
            CHỈ trả về một đối tượng JSON duy nhất theo cấu trúc schema, không thêm giải thích.
        `;

        const schema = {
            type: "OBJECT",
            properties: {
                storyTitle: { type: "STRING" },
                genre: { type: "STRING" },
                tags: { type: "STRING" },
                setting: { type: "STRING" },
                writingStyle: { type: "STRING", enum: WRITING_STYLES },
                currencyName: { type: "STRING" },
            },
            required: ["storyTitle", "genre", "tags", "setting", "writingStyle", "currencyName"]
        };

        const payload = {
            contents: [{ role: "user", parts: [{ text: prompt }] }],
            generationConfig: { response_mime_type: "application/json", response_schema: schema }
        };
        const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

        try {
            const response = await fetch(apiUrl, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
            const result = await response.json();
            if (result.candidates && result.candidates[0]?.content?.parts[0]?.text) {
                // Thêm try-catch để bắt lỗi parse JSON
                try {
                    return JSON.parse(result.candidates[0].content.parts[0].text);
                } catch (jsonError) {
                     console.error("Lỗi phân tích JSON từ fetchWorldInfo:", jsonError);
                     console.error("Phản hồi không hợp lệ từ AI:", result.candidates[0].content.parts[0].text);
                     throw new Error("AI trả về định dạng thông tin thế giới không hợp lệ.");
                }
            } else {
                const errorMsg = result.error?.message || "Không thể lấy thông tin thế giới từ AI.";
                throw new Error(errorMsg);
            }
        } catch (error) {
            console.error("Lỗi ở lượt gọi 1 (fetchWorldInfo):", error);
            setModalMessage({ show: true, title: 'Lỗi Tạo Thế Giới', content: `Không thể tạo thông tin cơ bản: ${error.message}`, type: 'error' });
            return null;
        }
    };
// Hàm cho LƯỢT GỌI 2: Tạo các thực thể dựa trên thông tin đã có
