const handleTargetSelection = (targetId) => {
    setIsProcessingAction(true);
    // BƯỚC 1: Lấy đầy đủ thông tin từ state, bao gồm cả flavorText đã được lưu
    const { skill, casterId, flavorText, companionCommand } = combatTargetingState;
    setCombatTargetingState({ isActive: false, skill: null, casterId: null });

    setTimeout(async () => {
        if (!activeCombatLoop || !skill || !casterId) {
            console.error("Lỗi handleTargetSelection: Trạng thái chiến đấu không hợp lệ.");
            setIsProcessingAction(false);
            return;
        }

        const turnTaker = activeCombatLoop.currentTurnTaker;
        if (!turnTaker || turnTaker.id !== casterId) {
            console.warn("Lỗi: Yêu cầu chọn mục tiêu không khớp với người đang hành động.");
            setIsProcessingAction(false);
            return;
        }

        const target = activeCombatLoop.allCombatants.find(c => c.id === targetId);
        if (!target) {
            console.error("Lỗi: Không tìm thấy mục tiêu đã chọn.");
            setIsProcessingAction(false);
            return;
        }

        // BƯỚC 2: Truyền flavorText và companionCommand đã lấy được vào handleActionRequest
        if (companionCommand) {
            activeCombatLoop.setNextCompanionCommand(companionCommand);
        }
        await handleActionRequest(turnTaker, false, { skillToUse: skill, target: target, isContinuation: true, flavorText: flavorText }, activeCombatLoop);
    }, 0);
};

