const checkForOverloadDrop = useCallback(() => {
    // Chỉ kiểm tra khi đang ở chế độ phiêu lưu
    if (gameMode !== 'EXPLORATION') return;
    
    // Sử dụng closure để lấy state mới nhất
    setknowledge(prevKnowledge => {
        const player = prevKnowledge.characters.find(c => c.isPlayer);
        if (!player) return prevKnowledge;

        const currentWeight = calculateCurrentWeight(player.inventory);
        const maxWeight = calculateMaxCarryWeight(player);

        if (currentWeight > maxWeight && maxWeight > 0 && player.inventory.length > 0) {
            const dropChance = 2 * (currentWeight - maxWeight) / maxWeight;
            
            if (Math.random() < dropChance) {
                // Tạo một bản sao sâu để tránh mutate state
                const newKnowledge = JSON.parse(JSON.stringify(prevKnowledge));
                const playerToUpdate = newKnowledge.characters.find(c => c.isPlayer);
                
                const randomIndex = Math.floor(Math.random() * playerToUpdate.inventory.length);
                const itemToDrop = playerToUpdate.inventory[randomIndex];
                
                // Xóa toàn bộ stack vật phẩm khỏi hành trang
                playerToUpdate.inventory.splice(randomIndex, 1);
                
                // Tạo thông báo và cập nhật storyHistory
                const message = `**[Hệ thống]** Vì mang vác quá nặng, ngươi đã vô tình đánh rơi ${itemToDrop.quantity > 1 ? itemToDrop.quantity + ' x ' : ''}${itemToDrop.Name}!`;
                setStoryHistory(prevHistory => [...prevHistory, { id: crypto.randomUUID(), type: 'system', content: message, transient: true }]);
                
                return newKnowledge; // Trả về knowledge đã được cập nhật
            }
        }
        
        return prevKnowledge; // Trả về knowledge không đổi nếu không có gì xảy ra
    });
}, [gameMode, setknowledge, setStoryHistory]); // <-- THAY ĐỔI CỐT LÕI NẰM Ở ĐÂY

useEffect(() => {
    // Điều kiện: chỉ chạy khi không phải lượt đầu tiên và là mỗi 2 lượt
    if (adventureTurnCount > 0 && adventureTurnCount % 2 === 0) {
        console.log(`Lượt phiêu lưu thứ ${adventureTurnCount}, tiến hành kiểm tra quá tải.`);
        checkForOverloadDrop();
    }
}, [adventureTurnCount, checkForOverloadDrop]);

useEffect(() => {
    // Chỉ thực thi khi có dữ liệu khởi tạo combat và chưa có combat loop nào đang chạy
    if (combatInitializationData && !activeCombatLoop) {
        const { playerParty, enemies, combatType } = combatInitializationData;

        const allCombatantsInvolved = [...playerParty, ...enemies].map(c => ({
            ...c,
            skills: c.skills || [],
        }));
        
        const finalStatCombatants = allCombatantsInvolved.map(c => calculateFinalStats(c));

        // KHỞI TẠO ĐÚNG THỨ TỰ THAM SỐ
        const loop = new CombatLoop(
            finalStatCombatants,        // 1. combatants
            handleCombatStateChange,    // 2. onStateChange
            handleActionRequest,        // 3. onActionRequest
            handleCombatEnd,            // 4. onCombatEnd
            combatType,                 // 5. combatType
            knowledge.sharedCooldowns,  // 6. sharedCooldowns
            async (animationData) => {  // 7. onAnimateAction
                setActiveAnimation(animationData);
                
                // Tính toán thời gian chờ (Dynamic Sleep) dựa trên độ dài hoạt ảnh
                const skill = animationData.skill;
                const vfx = skill.effects?.[0]?.action?.visual_effects || skill.visual_effects || {};
                const vfxCount = vfx.vfxCount || skill.effects?.[0]?.action?.target?.hit_count || 1;
                
                // TĂNG THỜI GIAN CHỜ LÊN ĐỂ ĐỢI VFX CHẠY XONG
                const baseDelay = 1000; 
                const timePerHit = 150; 
                
                let totalAnimationTime = baseDelay + (vfxCount * timePerHit);
                if (vfx.vfxType === 'curved_projectile' || vfx.vfxType === 'falling_object') {
                    totalAnimationTime += 300;
                }
                if (vfx.moveType === 'dash_through' || vfx.moveType === 'teleport') {
                    totalAnimationTime += 400; // Cộng thêm thời gian cho các hoạt ảnh di chuyển phức tạp
                }

                await sleep(totalAnimationTime);

                setActiveAnimation(null); // Reset để đón chiêu tiếp theo
            }
        );

        setActiveCombatLoop(loop);
        
        setTimeout(() => {
            loop.start();
        }, 100);

        setCombatInitializationData(null);
    }
  }, [combatInitializationData]); // Phụ thuộc vào state `combatInitializationData`

const handleSaveGame = async (includeImages = true) => {
   if (!storyHistory || storyHistory.length === 0) {
       setModalMessage({ show: true, title: 'Không Thể Lưu', content: 'Chưa có diễn biến nào để lưu lại.', type: 'info' });
       return;
   }

   let knowledgeToExport = JSON.parse(JSON.stringify(knowledge));
   if (knowledgeToExport.pendingModeChange) delete knowledgeToExport.pendingModeChange;

   // LOGIC TÙY CHỌN ẢNH
   if (includeImages) {
       setModalMessage({ show: true, title: 'Đang Đóng Gói...', content: 'Đang lấy dữ liệu hình ảnh từ bộ nhớ trình duyệt để xuất file (Việc này có thể mất vài giây)...', type: 'info' });
       try {
           await Promise.all(knowledgeToExport.characters.map(async (char) => {
               if (char.avatarStoredLocally && char.id) {
                   const base64 = await getAvatarFromIndexedDB(char.id);
                   if (base64) char.avatarBase64 = base64; 
               }
           }));
       } catch (e) {
           console.error("Lỗi khi đóng gói ảnh:", e);
       }
   } else {
       // Nếu chọn KHÔNG xuất ảnh, ta xóa sạch dấu vết ảnh trong file json để file nhẹ nhất có thể
       knowledgeToExport.characters.forEach(char => {
           char.avatarBase64 = null;
           // Vẫn giữ avatarStoredLocally = true để game biết là "máy này có ảnh", 
           // nhưng file json sẽ không chứa ảnh.
       });
   }

   const saveData = {
       id: currentGameId, 
       currentTurn: currentTurn,
       saveVersion: "2.7",
       timestamp: new Date().toISOString(),
       gameSettings,
       knowledge: knowledgeToExport,
       storyHistory, // Có thể cắt bớt nếu muốn file nhẹ hơn nữa
       choices,
       gameMode: gameMode,
       activeTrade: activeTrade, 
       storySummaries: storySummaries,
       adventureTurnCount: adventureTurnCount,
   };

   try {
       const jsonString = JSON.stringify(saveData, null, 2);
       const blob = new Blob([jsonString], { type: 'application/json' });
       const url = URL.createObjectURL(blob);
       const a = document.createElement('a');
       
       const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
       const safeThemeName = (gameSettings.theme || 'Story').replace(/[^a-z0-9]/gi, '_').substring(0, 20);
       
       // Đánh dấu tên file để dễ phân biệt
       const suffix = includeImages ? "FULL" : "LITE";
       a.href = url;
       a.download = `AI_PhieuLuu_${safeThemeName}_${timestamp}_${suffix}.json`;
       
       document.body.appendChild(a);
       a.click();
       document.body.removeChild(a);
       URL.revokeObjectURL(url);
       
       setModalMessage({ 
           show: true, 
           title: 'Xuất Tệp Thành Công', 
           content: includeImages 
               ? 'Đã xuất tệp thành công. Nếu muốn tiếp tục chơi sau khi thoát, hãy chọn nhập tệp.' 
               : 'Đã xuất tệp thành công. Nếu muốn tiếp tục chơi sau khi thoát, hãy chọn nhập tệp.', 
           type: 'success' 
       });
   } catch (error) {
       console.error("Lỗi khi tạo file tải về:", error);
       setModalMessage({ show: true, title: 'Lỗi Xuất File', content: error.message, type: 'error' });
   }
};

const handleClearImageCache = async () => {
    setConfirmationModal({
        show: true,
        title: 'Xóa Dữ Liệu Ảnh?',
        content: 'Hành động này sẽ xóa toàn bộ ảnh nhân vật được lưu trong trình duyệt này để giải phóng dung lượng.\n\nNhân vật vẫn còn, nhưng ảnh sẽ biến mất cho đến khi bạn tải lại file game có chứa ảnh (bản Full). Bạn có chắc không?',
        onConfirm: async () => {
            try {
                // Gọi hàm xóa IndexedDB
                const db = await openDB();
                const tx = db.transaction(STORE_NAME_AVATARS, 'readwrite');
                const store = tx.objectStore(STORE_NAME_AVATARS);
                const request = store.clear(); // Xóa sạch

                request.onsuccess = () => {
                    // Cập nhật lại state để giao diện biết là mất ảnh rồi
                    setknowledge(prev => {
                        const newK = JSON.parse(JSON.stringify(prev));
                        newK.characters.forEach(c => {
                            c.avatarStoredLocally = false;
                            c.avatarUrl = null;
                            c.avatarBase64 = null;
                        });
                        return newK;
                    });
                    setModalMessage({ show: true, title: 'Đã Dọn Dẹp', content: 'Đã xóa toàn bộ ảnh trong bộ nhớ trình duyệt.', type: 'success' });
                };
            } catch (e) {
                setModalMessage({ show: true, title: 'Lỗi', content: 'Không thể xóa cache: ' + e.message, type: 'error' });
            }
        },
        confirmText: 'Xóa Sạch Ảnh',
        cancelText: 'Hủy'
    });
};

const handleDeleteNpc = (npcId) => {
    setknowledge(prev => {
        const npcToDelete = prev.characters.find(c => c.id === npcId);
        if (!npcToDelete) return prev;

        const newKnowledge = JSON.parse(JSON.stringify(prev));
        newKnowledge.characters = newKnowledge.characters.filter(c => c.id !== npcId);
        
        // Cũng xóa khỏi lore nếu có
        if (newKnowledge.loreNpcs) {
            newKnowledge.loreNpcs = newKnowledge.loreNpcs.filter(lore => lore.name !== npcToDelete.Name);
        }

        setModalMessage({ show: true, title: 'Đã Xóa', content: `Đã xóa vĩnh viễn NPC "${npcToDelete.Name}" khỏi thế giới.`, type: 'success' });
        return newKnowledge;
    });
};

const handleCreateNpc = async (npcData) => {
    if (!npcData.name || !npcData.description) {
        setModalMessage({ show: true, title: 'Thiếu Thông Tin', content: 'Vui lòng nhập đầy đủ tên và mô tả cho NPC.', type: 'error' });
        return;
    }

    setIsProcessingAction(true);
    setModalMessage({ show: true, title: 'Đang Nặn Người...', content: `AI đang tạo ra NPC "${npcData.name}"...`, type: 'info' });

    const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";
    if (apiMode === 'userKey' && !effectiveApiKey) {
        setModalMessage({ show: true, title: 'Lỗi API Key', content: 'Vui lòng cấu hình API Key.', type: 'error' });
        setIsProcessingAction(false);
        return;
    }

    const playerLevel = knowledge.characters.find(c => c.isPlayer)?.level || 1;

    const prompt = `
        VAI TRÒ: Bạn là một nhà thiết kế nhân vật game.
        BỐI CẢNH: 
        - Thế giới game: "${gameSettings.theme}"
        - Cấp độ của người chơi hiện tại: ${playerLevel}

        YÊU CẦU: Dựa vào thông tin người dùng cung cấp dưới đây, hãy tạo ra một đối tượng NPC hoàn chỉnh.
        - Tên: "${npcData.name}"
        - Mô tả: "${npcData.description}"

        NHIỆM VỤ:
        1.  **Sáng tạo:** Dựa vào mô tả, hãy tự suy luận ra các thuộc tính sau cho NPC: 'level' (phải gần bằng hoặc thấp hơn cấp độ người chơi), 'Stance' (Thái độ ban đầu: Thân thiện, Thù địch, Trung lập), và 'Personality' (Tính cách).
        2.  **Định dạng:** Chỉ trả về một đối tượng JSON duy nhất chứa các thuộc tính: level, Stance, Personality.
    `;

    const schema = {
        type: "OBJECT",
        properties: {
            level: { type: "NUMBER" },
            Stance: { type: "STRING", enum: ["Thân thiện", "Thù địch", "Trung lập", "Sợ hãi", "Nghi ngờ"] },
            Personality: { type: "STRING" }
        },
        required: ["level", "Stance", "Personality"]
    };
    
    const payload = {
        contents: [{ role: "user", parts: [{ text: prompt }] }],
        generationConfig: { response_mime_type: "application/json", response_schema: schema }
    };
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

    try {
        const jsonText = await fetchWithRetries(apiUrl, payload);
        const aiData = JSON.parse(jsonText);

        setknowledge(prev => {
            const newKnowledge = JSON.parse(JSON.stringify(prev));
            
            // Hàm helper để tạo NPC đã có trong code của bạn, ta tái sử dụng
            let newNpc = {
                ...INITIAL_STATS,
                id: crypto.randomUUID(),
                isPlayer: false,
                isCompanion: false,
                Name: npcData.name,
                description: npcData.description,
                ...aiData
            };
            
            // Tính toán chỉ số gốc dựa trên level AI cho
            newNpc.baseHp = 200 + (newNpc.level - 1) * 20;
            newNpc.baseAtk = 20 + (newNpc.level - 1) * 2;
            newNpc.baseDef = 10 + (newNpc.level - 1) * 1;
            newNpc.baseSpd = 30 + (newNpc.level - 1) * 1;
            
            // Tính toán chỉ số cuối cùng
            const finalNpc = calculateFinalStats(newNpc);
            
            newKnowledge.characters.push(finalNpc);
            
            setModalMessage({ show: true, title: 'Tạo Thành Công', content: `NPC "${finalNpc.Name}" đã được thêm vào thế giới.`, type: 'success' });
            return newKnowledge;
        });

    } catch (error) {
        console.error("Lỗi khi tạo NPC:", error);
        setModalMessage({ show: true, title: 'Lỗi AI', content: `Không thể tạo NPC: ${error.message}`, type: 'error' });
    } finally {
        setIsProcessingAction(false);
    }
};

const handleRenameNpc = useCallback((npcId, newName, newDescription) => {
    if (!newName || !newName.trim()) {
        setModalMessage({ show: true, title: "Lỗi", content: "Tên NPC không được để trống.", type: "error" });
        return;
    }

    setknowledge(prev => {
        const newKnowledge = JSON.parse(JSON.stringify(prev));
        const charIndex = newKnowledge.characters.findIndex(c => c.id === npcId);

        if (charIndex > -1) {
            const oldName = newKnowledge.characters[charIndex].Name;
            newKnowledge.characters[charIndex].Name = newName.trim();
            if (newDescription !== undefined) {
                newKnowledge.characters[charIndex].description = newDescription.trim();
            }
            setModalMessage({ show: true, title: "Cập Nhật Thành Công", content: `Đã đổi tên NPC "${oldName}" thành "${newName.trim()}".`, type: "success" });
        }
        return newKnowledge;
    });
}, [setModalMessage]);

const handleLoadSetupFromFile = (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const loadedData = JSON.parse(e.target.result);
            // Kiểm tra xem tệp có đúng định dạng không
            if (!loadedData.setupVersion || !loadedData.settings) {
                throw new Error("Tệp không phải là tệp lưu thiết lập hợp lệ.");
            }

            // Cập nhật lại toàn bộ gameSettings
            setGameSettings(loadedData.settings);

            setModalMessage({ show: true, title: 'Thành Công', content: 'Đã tải thiết lập thành công!', type: 'success' });
        } catch (error) {
            console.error("Lỗi khi tải tệp thiết lập:", error);
            setModalMessage({ show: true, title: 'Lỗi Tải Tệp', content: `Không thể đọc tệp thiết lập: ${error.message}`, type: 'error' });
        }
    };
    reader.readAsText(file);
    // Reset giá trị của input để có thể chọn lại cùng một tệp
    event.target.value = null;
};

const handleDeleteLocation = (locationId) => {
    setknowledge(prev => {
        const locationToDelete = prev.locations.find(loc => loc.id === locationId);
        if (!locationToDelete) return prev;

        const newKnowledge = JSON.parse(JSON.stringify(prev));
        newKnowledge.locations = newKnowledge.locations.filter(loc => loc.id !== locationId);

        if (newKnowledge.loreLocations) {
            newKnowledge.loreLocations = newKnowledge.loreLocations.filter(lore => lore.name !== locationToDelete.Name);
        }

        setModalMessage({ show: true, title: 'Đã Xóa', content: `Đã xóa vĩnh viễn địa điểm "${locationToDelete.Name}" khỏi thế giới.`, type: 'success' });
        return newKnowledge;
    });
};

