const sanitizeDataForFirestore = (data) => {
    // 1. Chuyển undefined thành null (Firestore KHÔNG chịu undefined)
    if (data === undefined) return null;

    // 2. Giữ nguyên null và các kiểu dữ liệu cơ bản
    if (data === null || typeof data !== 'object') return data;

    // 3. Xử lý đối tượng đặc biệt của Firebase (serverTimestamp...)
    if (data.constructor && data.constructor !== Object && data.constructor !== Array) {
        return data;
    }

    // 4. Xử lý Mảng (Array) - QUAN TRỌNG
    if (Array.isArray(data)) {
        return data
            .map(item => sanitizeDataForFirestore(item)) // Đệ quy làm sạch con
            .filter(item => item !== undefined); // Lọc bỏ hoàn toàn rác
    }

    // 5. Xử lý Đối tượng (Object)
    const sanitizedObject = {};
    for (const key in data) {
        if (Object.prototype.hasOwnProperty.call(data, key)) {
            const value = data[key];
            
            // Loại bỏ function và các key "nặng" không cần thiết khi lưu cloud
            if (typeof value === 'function') continue;
            
            // QUAN TRỌNG: Cố tình bỏ qua trường chứa ảnh Base64 để file nhẹ
            if (key === 'avatarBase64') continue; 

            const cleanValue = sanitizeDataForFirestore(value);
            if (cleanValue !== undefined) {
                sanitizedObject[key] = cleanValue;
            }
        }
    }
    return sanitizedObject;
};

useEffect(() => {
    if (justExitedCombat) {
        setJustExitedCombat(false); 
        return;
    }

    if (currentTurn > 1 && currentScreen === 'gameplay' && gameMode === 'EXPLORATION') {
        const systemMessages = [];
 
        setknowledge(prev => {
            const newKnowledge = JSON.parse(JSON.stringify(prev));
 
            if (newKnowledge.sharedCooldowns) {
                if (newKnowledge.sharedCooldowns.tactical > 0) {
                    newKnowledge.sharedCooldowns.tactical -= 1;
                }
                if (newKnowledge.sharedCooldowns.potion > 0) {
                    newKnowledge.sharedCooldowns.potion -= 1;
                }
            }
 
            newKnowledge.characters = newKnowledge.characters.map(char => {
                if (char.isPermanentlyDead) return char; // Bỏ qua nhân vật đã chết

                let updatedChar = { ...char };
                const statuses = updatedChar.longTermStatuses || [];
                let isBleeding = false;
                let bleedinghpLoss = 0;
 
                if (updatedChar.isPlayer && updatedChar.skills) {
                    updatedChar.skills = updatedChar.skills.map(skill => ({
                        ...skill,
                        currentCooldown: Math.max(0, (skill.currentCooldown || 0) - 1)
                    }));
                }
 
                if (statuses.length > 0) {
                    updatedChar.longTermStatuses = statuses.map(status => {
                        const template = LONG_TERM_STATUS_TEMPLATES[status.status_id] || status;

                        if (template.effects_per_day?.hp_percent_loss) {
                             isBleeding = true;
                             bleedinghpLoss += (updatedChar.maxhp || 0) * (template.effects_per_day.hp_percent_loss / 100.0);
                        }

                        if (typeof status.duration === 'number' && status.duration > 0) {
                            status.duration -= 1;
                            if (status.duration <= 0) {
                                 systemMessages.push({ type: 'system', content: `**[Hệ thống]** Trạng thái "${status.name}" trên ${updatedChar.Name} đã kết thúc.` });
                                 return null;
                            }
                        }
                        return status;
                    }).filter(Boolean);
                }
 
                if (isBleeding) {
                    updatedChar.hp = Math.max(0, (updatedChar.hp || 0) - Math.floor(bleedinghpLoss));
                    if (bleedinghpLoss > 0) {
                        systemMessages.push({ type: 'system', content: `**[Hệ thống]** ${updatedChar.Name} mất ${Math.floor(bleedinghpLoss)} sinh lực do vết thương.` });
                    }
                }
                
                return updatedChar;
            });
            
            return newKnowledge;
        });
 
        if (systemMessages.length > 0) {
            setStoryHistory(prevHistory => [
                ...prevHistory,
                ...systemMessages.map(msg => ({...msg, id: crypto.randomUUID(), transient: true}))
            ]);
        }
    }
}, [currentTurn, gameMode, justExitedCombat]);

