//        // Ví dụ 2: Ngươi dùng đan dược quý để chữa trọng thương.
//        [CHARACTER_UPDATE: Name="Ngươi", Stats="hp:+250,longtermstatuses:-'Trọng Thương',inventory:-'Cửu Chuyển Hoàn Hồn Đan'"]
//        // Ví dụ 3: A Ly đồng ý trở thành đồng hành của ngươi.
