    // Hàm tính tổng sức chứa tối đa của hành trang
const calculateMaxCarryWeight = (character) => {
    const BASE_CARRY_WEIGHT = 20;
    let flatBonus = 0;
    let percentBonus = 0;

    // Duyệt qua tất cả các trang bị đã mặc để tìm bonus
    const equippedItems = Object.values(character?.equippedItems || {}).filter(Boolean);
    
    equippedItems.forEach(item => {
        if (item && item.Stats) {
            const bonuses = parseKeyValueString(item.Stats);
            if (bonuses.carry_weight) {
                flatBonus += parseInt(bonuses.carry_weight, 10);
            }
            if (bonuses.carry_weight_percent) {
                percentBonus += parseInt(bonuses.carry_weight_percent, 10);
            }
        }
    });

    // Công thức tính: (Sức chứa cơ bản + Sức chứa cộng thẳng) * (1 + % Sức chứa)
    const maxWeight = (BASE_CARRY_WEIGHT + flatBonus) * (1 + percentBonus / 100);

    return maxWeight;
};


    // Hàm tính tổng trọng lượng hiện tại của các vật phẩm trong hành trang
const calculateCurrentWeight = (inventory) => {
        if (!inventory || inventory.length === 0) {
            return 0;
        }
        
        const totalWeight = inventory.reduce((sum, item) => {
            // Chuyển đổi weight sang số và cộng dồn, nếu không phải số thì coi là 0
            const itemWeight = parseFloat(item.Weight || 0);
            return sum + (isNaN(itemWeight) ? 0 : itemWeight);
        }, 0);

        // Làm tròn đến 1 chữ số thập phân cho đẹp
        return parseFloat(totalWeight.toFixed(1));
};



